function LoginScreen({ onLogin }) {
  const [email, setEmail]       = useState("");
  const [sent, setSent]         = useState(false);
  const [loading, setLoading]   = useState(false);
  const [error, setError]       = useState("");
  const [guestName, setGuestName] = useState("");
  const [showGuest, setShowGuest] = useState(false);

  const sendLink = async () => {
    if (!email.trim() || !email.includes("@")) {
      setError("Enter a valid email address."); return;
    }
    setLoading(true); setError("");
    const result = await sbSignInWithEmail(email.trim().toLowerCase());
    setLoading(false);
    if (result.success) { setSent(true); }
    else { setError(result.error || "Failed to send link. Try again."); }
  };

  const continueAsGuest = () => {
    const name = guestName.trim() || "Guest";
    const guestUser = { id:"guest_" + Date.now(), email:"guest@local", user_metadata:{ name } };
    onLogin({ user:guestUser, access_token:"guest" });
  };

  return (
    <div style={{ position:"fixed", inset:0, background:"#0f1117",
      display:"flex", alignItems:"center", justifyContent:"center",
      fontFamily:"'IBM Plex Sans','Helvetica Neue',sans-serif", zIndex:999 }}>
      <style>{`@keyframes fadeUp{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:none}}`}</style>

      <div style={{ width:"100%", maxWidth:420, padding:"0 24px", animation:"fadeUp .4s ease" }}>
        {/* Logo */}
        <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:40 }}>
          <div style={{ width:36, height:36, borderRadius:9,
            background:"linear-gradient(135deg,#2563eb,#7c3aed)",
            display:"flex", alignItems:"center", justifyContent:"center" }}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none"
              stroke="#fff" strokeWidth="2.5" strokeLinecap="round">
              <path d="M12 2L2 7l10 5 10-5-10-5z"/>
              <path d="M2 17l10 5 10-5"/>
              <path d="M2 12l10 5 10-5"/>
            </svg>
          </div>
          <div>
            <div style={{ fontSize:18, fontWeight:700, color:"#f1f5f9",
              fontFamily:"'Libre Baskerville',serif" }}>Vantage DQ</div>
            <div style={{ fontSize:10, color:"#475569", letterSpacing:1.5,
              textTransform:"uppercase" }}>Decision Platform</div>
          </div>
        </div>

        {!sent ? (
          <div>
            <div style={{ fontSize:22, fontWeight:700, color:"#f1f5f9",
              fontFamily:"'Libre Baskerville',serif", marginBottom:8 }}>
              Sign in
            </div>
            <div style={{ fontSize:13, color:"#64748b", marginBottom:28, lineHeight:1.6 }}>
              Enter your email and we'll send you a magic link -- no password needed.
            </div>

            <div style={{ marginBottom:12 }}>
              <input
                type="email"
                value={email}
                onChange={e=>setEmail(e.target.value)}
                onKeyDown={e=>e.key==="Enter"&&sendLink()}
                placeholder="your@email.com"
                autoFocus
                style={{ width:"100%", padding:"12px 14px", fontSize:14,
                  fontFamily:"inherit", background:"rgba(255,255,255,.07)",
                  border:"1px solid rgba(255,255,255,.12)", borderRadius:8,
                  color:"#f1f5f9", outline:"none", boxSizing:"border-box",
                  transition:"border-color .15s" }}
                onFocus={e=>e.target.style.borderColor="#3b82f6"}
                onBlur={e=>e.target.style.borderColor="rgba(255,255,255,.12)"}/>
            </div>

            {error && (
              <div style={{ fontSize:12, color:"#fca5a5", marginBottom:10 }}>{error}</div>
            )}

            <button onClick={sendLink} disabled={loading}
              style={{ width:"100%", padding:"12px", fontSize:13, fontWeight:700,
                fontFamily:"inherit", border:"none", borderRadius:8, cursor:"pointer",
                background:"linear-gradient(135deg,#2563eb,#3b82f6)",
                color:"#fff", opacity:loading?0.7:1, transition:"opacity .15s" }}>
              {loading ? "Sending…" : "Send Magic Link →"}
            </button>

            <div style={{ margin:"20px 0", display:"flex", alignItems:"center", gap:12 }}>
              <div style={{ flex:1, height:1, background:"rgba(255,255,255,.08)" }}/>
              <span style={{ fontSize:11, color:"#475569" }}>or</span>
              <div style={{ flex:1, height:1, background:"rgba(255,255,255,.08)" }}/>
            </div>

            {!showGuest ? (
              <button onClick={()=>setShowGuest(true)}
                style={{ width:"100%", padding:"11px", fontSize:12, fontWeight:600,
                  fontFamily:"inherit", border:"1px solid rgba(255,255,255,.1)",
                  borderRadius:8, cursor:"pointer", background:"transparent",
                  color:"#64748b", transition:"all .15s" }}
                onMouseEnter={e=>{e.target.style.borderColor="rgba(255,255,255,.2)";e.target.style.color="#94a3b8";}}
                onMouseLeave={e=>{e.target.style.borderColor="rgba(255,255,255,.1)";e.target.style.color="#64748b";}}>
                Continue as Guest
              </button>
            ) : (
              <div style={{ display:"flex", gap:8 }}>
                <input value={guestName} onChange={e=>setGuestName(e.target.value)}
                  onKeyDown={e=>e.key==="Enter"&&continueAsGuest()}
                  placeholder="Your name (optional)"
                  autoFocus
                  style={{ flex:1, padding:"11px 12px", fontSize:12, fontFamily:"inherit",
                    background:"rgba(255,255,255,.06)", border:"1px solid rgba(255,255,255,.1)",
                    borderRadius:7, color:"#f1f5f9", outline:"none" }}/>
                <button onClick={continueAsGuest}
                  style={{ padding:"11px 16px", fontSize:12, fontWeight:700,
                    fontFamily:"inherit", border:"1px solid rgba(255,255,255,.15)",
                    borderRadius:7, background:"transparent", color:"#94a3b8",
                    cursor:"pointer" }}>
                  Go →
                </button>
              </div>
            )}
          </div>
        ) : (
          <div style={{ textAlign:"center" }}>
            <div style={{ fontSize:40, marginBottom:20 }}>📬</div>
            <div style={{ fontSize:20, fontWeight:700, color:"#f1f5f9",
              fontFamily:"'Libre Baskerville',serif", marginBottom:10 }}>
              Check your email
            </div>
            <div style={{ fontSize:13, color:"#64748b", lineHeight:1.7, marginBottom:28 }}>
              We sent a magic link to <strong style={{color:"#94a3b8"}}>{email}</strong>.
              Click the link to sign in -- it expires in 1 hour.
            </div>
            <button onClick={()=>{setSent(false);setError("");}}
              style={{ fontSize:12, color:"#475569", background:"none",
                border:"none", cursor:"pointer", textDecoration:"underline",
                fontFamily:"inherit" }}>
              Use a different email
            </button>
          </div>
        )}
      </div>
    </div>
  );
}

function CommentsPanel({ decisionId, module, currentUser, onClose }) {
  const [comments, setComments]   = useState([]);
  const [text, setText]           = useState("");
  const [sending, setSending]     = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => {
    if (!decisionId) return;
    sbGetComments(decisionId, module).then(setComments);
  }, [decisionId, module]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior:"smooth" });
  }, [comments]);

  const send = async () => {
    if (!text.trim() || !decisionId) return;
    setSending(true);
    const name = currentUser?.user_metadata?.name ||
      currentUser?.email?.split("@")[0] || "Anonymous";
    const comment = await sbAddComment(
      decisionId, module, text.trim(),
      currentUser?.email, name
    );
    if (comment) setComments(prev => [...prev, comment]);
    setText("");
    setSending(false);
  };

  const userName = (c) => c.author_name || c.author_email?.split("@")[0] || "Anonymous";
  const initials = (c) => userName(c).slice(0,2).toUpperCase();
  const timeAgo = (ts) => {
    const d = Math.floor((Date.now() - new Date(ts)) / 1000);
    if (d < 60) return "just now";
    if (d < 3600) return Math.floor(d/60) + "m ago";
    if (d < 86400) return Math.floor(d/3600) + "h ago";
    return new Date(ts).toLocaleDateString("en-GB",{day:"numeric",month:"short"});
  };

  const COLORS = ["#2563eb","#7c3aed","#059669","#d97706","#dc2626","#0891b2"];
  const colorFor = (email) => COLORS[(email||"").charCodeAt(0) % COLORS.length];

  return (
    <div style={{ width:300, height:"100%", borderLeft:"1px solid",
      borderColor:"var(--canvasBdr, #e2e8f0)",
      background:"var(--canvas, #ffffff)",
      display:"flex", flexDirection:"column",
      fontFamily:"'IBM Plex Sans','Helvetica Neue',sans-serif" }}>

      {/* Header */}
      <div style={{ padding:"12px 16px", borderBottom:"1px solid",
        borderColor:"var(--canvasBdr, #e2e8f0)",
        display:"flex", alignItems:"center", gap:8 }}>
        <div style={{ flex:1, fontSize:12, fontWeight:700,
          color:"var(--ink, #1e293b)" }}>
          💬 Comments
          {comments.length > 0 && (
            <span style={{ marginLeft:6, fontSize:10,
              color:"var(--inkTer, #94a3b8)" }}>
              {comments.length}
            </span>
          )}
        </div>
        <button onClick={onClose}
          style={{ background:"none", border:"none", cursor:"pointer",
            color:"var(--inkTer, #94a3b8)", fontSize:16 }}>×</button>
      </div>

      {/* Comments list */}
      <div style={{ flex:1, overflowY:"auto", padding:"12px 16px" }}>
        {comments.length === 0 ? (
          <div style={{ textAlign:"center", padding:"32px 0",
            color:"var(--inkTer, #94a3b8)", fontSize:12 }}>
            No comments yet.<br/>Be the first to add one.
          </div>
        ) : (
          comments.map(comment => (
            <div key={comment.id} style={{ marginBottom:14 }}>
              <div style={{ display:"flex", alignItems:"flex-start", gap:8 }}>
                <div style={{ width:28, height:28, borderRadius:"50%",
                  background:colorFor(comment.author_email),
                  display:"flex", alignItems:"center", justifyContent:"center",
                  fontSize:10, fontWeight:700, color:"#fff", flexShrink:0 }}>
                  {initials(comment)}
                </div>
                <div style={{ flex:1 }}>
                  <div style={{ display:"flex", alignItems:"baseline", gap:6, marginBottom:3 }}>
                    <span style={{ fontSize:11, fontWeight:700,
                      color:"var(--ink, #1e293b)" }}>{userName(comment)}</span>
                    <span style={{ fontSize:9,
                      color:"var(--inkTer, #94a3b8)" }}>
                      {timeAgo(comment.created_at)}
                    </span>
                  </div>
                  <div style={{ fontSize:12, color:"var(--inkSub, #475569)",
                    lineHeight:1.5, padding:"7px 10px",
                    background:"var(--canvasAlt, #f8fafc)",
                    borderRadius:"0 8px 8px 8px",
                    border:"1px solid var(--canvasBdr, #e2e8f0)" }}>
                    {comment.text}
                  </div>
                </div>
              </div>
            </div>
          ))
        )}
        <div ref={bottomRef}/>
      </div>

      {/* Input */}
      <div style={{ padding:"10px 16px",
        borderTop:"1px solid var(--canvasBdr, #e2e8f0)" }}>
        <div style={{ display:"flex", gap:6 }}>
          <textarea
            value={text}
            onChange={e=>setText(e.target.value)}
            onKeyDown={e=>{ if(e.key==="Enter"&&!e.shiftKey){ e.preventDefault(); send(); } }}
            placeholder="Add a comment… (Enter to send)"
            rows={2}
            style={{ flex:1, padding:"7px 10px", fontSize:12,
              fontFamily:"inherit", resize:"none", outline:"none",
              background:"var(--canvasAlt, #f8fafc)",
              border:"1px solid var(--canvasBdr, #e2e8f0)",
              borderRadius:6, color:"var(--ink, #1e293b)",
              lineHeight:1.5, boxSizing:"border-box" }}/>
          <button onClick={send} disabled={sending||!text.trim()}
            style={{ padding:"7px 12px", fontSize:11, fontWeight:700,
              fontFamily:"inherit", border:"none", borderRadius:6,
              background:"#2563eb", color:"#fff", cursor:"pointer",
              alignSelf:"flex-end", opacity:sending||!text.trim()?0.5:1 }}>
            {sending ? "…" : "↑"}
          </button>
        </div>
      </div>
    </div>
  );
}

function PresenceBar({ presence }) {
  if (!presence || presence.length === 0) return null;
  const COLORS = ["#2563eb","#7c3aed","#059669","#d97706","#dc2626","#0891b2"];
  const colorFor = (email) => COLORS[(email||"").charCodeAt(0) % COLORS.length];
  return (
    <div style={{ display:"flex", alignItems:"center", gap:4, padding:"4px 0" }}>
      {presence.slice(0,5).map((p,i) => (
        <div key={i} title={p.name + (p.module ? " -- " + p.module : "")}
          style={{ width:24, height:24, borderRadius:"50%",
            background:colorFor(p.email),
            border:"2px solid white",
            display:"flex", alignItems:"center", justifyContent:"center",
            fontSize:9, fontWeight:700, color:"#fff",
            marginLeft:i>0?-6:0, cursor:"default" }}>
          {(p.name||p.email||"?").slice(0,2).toUpperCase()}
        </div>
      ))}
      {presence.length > 5 && (
        <div style={{ fontSize:9, color:"#94a3b8", marginLeft:4 }}>
          +{presence.length-5}
        </div>
      )}
    </div>
  );
}

function QuickStartScreen({ onComplete, onSkip }) {
  const [phase, setPhase] = useState("landing");
  const [inputMode, setInputMode] = useState("paste");
  const [rawText, setRawText] = useState("");
  const [guidedAnswers, setGuidedAnswers] = useState({ frame:"", trigger:"", options:"", regret:"", alignment:"" });
  const [analysisProgress, setAnalysisProgress] = useState([]);
  const [draft, setDraft] = useState(null);
  const [accepted, setAccepted] = useState({});
  const [dragOver, setDragOver] = useState(false);
  const [rerunInstruction, setRerunInstruction] = useState("");
  const [activeReviewTab, setActiveReviewTab] = useState("frame");
  const [exportingReport, setExportingReport] = useState(false);
  const { busy, call } = useAI();

  const generateDeepDiveReport = (d) => {
    if (!d) return "<html><body>No draft available.</body></html>";
    const section = (title, content) => content ?
      `<div class="section"><h2>${title}</h2>${content}</div>` : "";
    const tag = (label, col) =>
      `<span style="display:inline-block;padding:2px 8px;border-radius:4px;font-size:10px;font-weight:700;background:${col}20;color:${col};margin:2px">${label}</span>`;
    const flagCol = {critical:"#dc2626",warning:"#d97706",info:"#6b7280"};
    return `<!DOCTYPE html><html><head><meta charset="utf-8">
      <title>Deep Dive Analysis -- ${d.projectName||"Decision"}</title>
      <style>
        body{font-family:'Helvetica Neue',Arial,sans-serif;max-width:900px;margin:40px auto;padding:0 24px;color:#1e293b;font-size:14px;line-height:1.6}
        h1{font-size:28px;font-weight:800;color:#1b2a4a;border-bottom:3px solid #2563eb;padding-bottom:12px;margin-bottom:8px}
        h2{font-size:16px;font-weight:700;color:#2563eb;margin:28px 0 10px;border-left:4px solid #2563eb;padding-left:10px}
        h3{font-size:13px;font-weight:700;color:#334155;margin:16px 0 6px}
        .section{margin-bottom:28px;padding:16px 20px;border:1px solid #e2e8f0;border-radius:8px;background:#f8fafc}
        .meta{font-size:12px;color:#64748b;margin-bottom:20px}
        .grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin:10px 0}
        .score-box{text-align:center;padding:10px;border:1px solid #e2e8f0;border-radius:6px;background:#fff}
        .score-num{font-size:28px;font-weight:800}
        .item{padding:8px 12px;border-left:3px solid #2563eb;margin-bottom:8px;background:#fff;border-radius:0 6px 6px 0}
        .flag{padding:8px 12px;margin-bottom:6px;border-radius:6px;background:#fff;border:1px solid #e2e8f0}
        table{width:100%;border-collapse:collapse;font-size:12px;margin:8px 0}
        th{background:#1b2a4a;color:#fff;padding:6px 10px;text-align:left}
        td{padding:6px 10px;border-bottom:1px solid #e2e8f0}
        tr:nth-child(even) td{background:#f8fafc}
        .verdict{display:inline-block;padding:4px 14px;border-radius:20px;font-weight:700;font-size:12px}
        @media print{.section{break-inside:avoid}}
      </style></head><body>
      <h1>Deep Dive Analysis Report</h1>
      <div class="meta">Project: <strong>${d.projectName||"Untitled"}</strong> · Generated: ${new Date().toLocaleDateString("en-GB",{day:"numeric",month:"long",year:"numeric"})}</div>

      ${section("Executive Summary", d.executiveSummary ? `<p>${d.executiveSummary}</p>` : "")}

      ${section("Decision Frame", d.frame ? `
        <table><tr><th>Field</th><th>Value</th></tr>
        ${[["Decision Statement",d.frame.decisionStatement],["Owner",d.frame.owner],["Deadline",d.frame.deadline],
          ["Trigger",d.frame.trigger],["Scope In",d.frame.scopeIn],["Scope Out",d.frame.scopeOut],
          ["Constraints",d.frame.constraints],["Success Criteria",d.frame.successCriteria]]
          .filter(([,v])=>v).map(([l,v])=>`<tr><td><strong>${l}</strong></td><td>${v}</td></tr>`).join("")}
        </table>` : "")}

      ${section("DQ Scorecard", d.dqScores ? `
        <div style="margin-bottom:10px">
          ${d.readinessVerdict ? `<span class="verdict" style="background:${d.readinessVerdict==="ready"?"#dcfce7":d.readinessVerdict==="conditional"?"#fef9c3":"#fee2e2"};color:${d.readinessVerdict==="ready"?"#15803d":d.readinessVerdict==="conditional"?"#92400e":"#dc2626"}">${d.readinessVerdict==="ready"?"Decision Ready":d.readinessVerdict==="conditional"?"Conditionally Ready":"Not Ready"}</span>` : ""}
        </div>
        <div class="grid">
          ${[["Frame",d.dqScores.frame],["Alternatives",d.dqScores.alternatives],["Information",d.dqScores.information],
             ["Values",d.dqScores.values],["Reasoning",d.dqScores.reasoning],["Commitment",d.dqScores.commitment]].map(([l,s])=>{
            const col = s>=70?"#059669":s>=45?"#d97706":"#dc2626";
            return `<div class="score-box"><div style="font-size:11px;color:#64748b">${l}</div><div class="score-num" style="color:${col}">${s||0}</div></div>`;
          }).join("")}
        </div>
        ${d.dqNarrative ? `<p style="font-style:italic;color:#64748b">${d.dqNarrative}</p>` : ""}` : "")}

      ${section("Validation Flags", d.validationFlags?.length ? `
        ${d.validationFlags.map(f=>`<div class="flag"><span style="display:inline-block;padding:1px 6px;border-radius:3px;font-size:10px;font-weight:700;background:${(flagCol[f.severity]||"#6b7280")}20;color:${flagCol[f.severity]||"#6b7280"};margin-right:8px">${f.severity}</span>${f.message}${f.suggestion?`<div style="font-size:11px;color:#2563eb;margin-top:2px">→ ${f.suggestion}</div>`:""}</div>`).join("")}` : "")}

      ${section("Strategies", d.strategies?.length ? `
        <table><tr><th>Name</th><th>Description</th><th>Key Assumption</th></tr>
        ${d.strategies.map(s=>`<tr><td><strong>${s.name}</strong></td><td>${s.description||""}</td><td><em>${s.keyAssumption||""}</em></td></tr>`).join("")}
        </table>` : "")}

      ${section("Issues", [...(d.issues||[]),...(d.brutalTruths||[]).map(b=>({...b,category:"brutal-truth"})),...(d.informationGaps||[]).map(g=>({...g,category:"information-gap"}))].length ? `
        <table><tr><th>Issue</th><th>Category</th><th>Severity</th><th>Source</th></tr>
        ${[...(d.issues||[]),...(d.brutalTruths||[]).map(b=>({...b,category:"brutal-truth"})),...(d.informationGaps||[]).map(g=>({...g,category:"information-gap"}))]
          .map(i=>`<tr><td>${i.text}</td><td>${i.category||""}</td><td>${i.severity||""}</td><td><em>${i.source||""}</em></td></tr>`).join("")}
        </table>` : "")}

      ${section("Stakeholders", d.stakeholders?.length ? `
        <table><tr><th>Name</th><th>Role</th><th>Influence</th><th>Alignment</th><th>Primary Concern</th></tr>
        ${d.stakeholders.map(s=>`<tr><td><strong>${s.name}</strong></td><td>${s.role||""}</td><td>${s.influence||""}</td><td>${s.alignment||""}</td><td>${s.primaryConcern||""}</td></tr>`).join("")}
        </table>` : "")}

      ${section("Value of Information", d.voiItems?.length ? `
        <table><tr><th>Uncertainty</th><th>Classification</th><th>Action</th><th>Timeline</th></tr>
        ${d.voiItems.map(v=>`<tr><td><strong>${v.label}</strong><br><span style="font-size:11px;color:#64748b">${v.description||""}</span></td><td>${tag({do_now:"Do Now",do_later:"Do Later",conditional:"If Trigger",do_not_do:"Do Not Do"}[v.classification]||v.classification,"#6b7280")}</td><td>${v.action||""}</td><td>${v.timeToLearn||""}</td></tr>`).join("")}
        </table>
        ${d.voiSummary ? `<p style="font-style:italic;color:#64748b">${d.voiSummary}</p>` : ""}` : "")}

      ${section("Risk Timeline", d.timelineEvents?.length ? `
        <table><tr><th>Month</th><th>Event</th><th>Type</th><th>Severity</th><th>Mitigation</th></tr>
        ${d.timelineEvents.sort((a,b)=>(a.timing||0)-(b.timing||0)).map(ev=>`<tr><td><strong>M${ev.timing||"?"}</strong></td><td>${ev.title}<br><span style="font-size:11px;color:#64748b">${ev.description||""}</span></td><td>${ev.type?.replace("_"," ")||""}</td><td>${ev.severity||""}</td><td>${ev.mitigation||""}</td></tr>`).join("")}
        </table>
        ${d.criticalPath ? `<p><strong>Critical path:</strong> ${d.criticalPath}</p>` : ""}` : "")}

      ${section("Cross-Module Intelligence", d.crossModuleInsights ? `
        ${d.crossModuleInsights.contradictions?.length ? `<h3>Contradictions</h3>${d.crossModuleInsights.contradictions.map(x=>`<div class="item">${x}</div>`).join("")}` : ""}
        ${d.crossModuleInsights.orphanRisks?.length ? `<h3>Orphan Risks</h3>${d.crossModuleInsights.orphanRisks.map(x=>`<div class="item">${x}</div>`).join("")}` : ""}
        ${d.crossModuleInsights.strategicTensions?.length ? `<h3>Strategic Tensions</h3>${d.crossModuleInsights.strategicTensions.map(x=>`<div class="item">${x}</div>`).join("")}` : ""}
        ${d.crossModuleInsights.missingDownstreamAnalysis?.length ? `<h3>Missing Downstream Analysis</h3>${d.crossModuleInsights.missingDownstreamAnalysis.map(x=>`<div class="item">${x}</div>`).join("")}` : ""}` : "")}

      <div style="margin-top:40px;padding-top:20px;border-top:1px solid #e2e8f0;font-size:11px;color:#94a3b8;text-align:center">
        Vantage DQ -- Deep Dive Analysis Report · vantage-dq.vercel.app · ${new Date().toLocaleDateString()}
      </div>
    </body></html>`;
  };

  const GUIDED_QUESTIONS = [
    {
      key: "frame",
      label: "If we walk out of this process with a great outcome, what decision will we have confidently made?",
      placeholder: "Describe the decision as if it has already been resolved -- what choice was made, by whom, and with what level of confidence?\n\nExample: \"We will have decided to enter APAC through a strategic partnership rather than a direct subsidiary -- with clear partner criteria agreed, a budget ceiling set, and the board aligned on a 24-month horizon.\"",
    },
    {
      key: "trigger",
      label: "What problem, opportunity, tension, or trigger is making this decision necessary right now?",
      placeholder: "What is forcing this onto the agenda? Is it an external event, internal tension, a missed opportunity, or a looming deadline?\n\nExample: \"A key competitor moved into APAC 14 months ago and is taking market share. Internally, our growth targets require a new region by FY26. There is tension between the CFO (capital caution) and the CEO (speed to market).\"",
    },
    {
      key: "options",
      label: "What are the real choices available to us -- including doing nothing or delaying action?",
      placeholder: "List every serious option on the table. Include the status quo. Don't pre-filter -- even options that seem unlikely may matter.\n\nExample: \"(1) Direct subsidiary in Singapore, (2) Acquire a regional player, (3) Strategic partnership with a local firm, (4) Delay 12 months and gather more data, (5) Licence our technology to an APAC operator.\"",
    },
    {
      key: "regret",
      label: "What could make us regret this decision in the future?",
      placeholder: "Think forward: what risks, assumptions, blind spots, or stakeholder conflicts could come back to haunt this decision? Be honest about what you don't know.\n\nExample: \"If demand doesn't materialise, we've committed $25M we can't recover. If we pick the wrong partner, we lose 2 years and our reputation. We're also assuming regulatory stability -- which is uncertain. The board may lose confidence if milestones slip.\"",
    },
    {
      key: "alignment",
      label: "Who needs to be aligned for this decision to succeed -- and what constraints or realities must we respect?",
      placeholder: "Name the key stakeholders, decision-makers, and influencers. Then list the hard constraints -- budget, regulation, capability, political realities -- that bound the solution space.\n\nExample: \"Board must approve >$10M. CFO needs a credible payback model. Legal must clear regulatory exposure. Hard constraints: $25M Year 1 cap, no more than 30 new hires, must comply with APAC data residency laws.\"",
    },
  ];

  const getInputText = () => {
    if (inputMode === "paste") return rawText;
    return Object.entries(guidedAnswers).map(([k, v]) => {
      const q = GUIDED_QUESTIONS.find(g => g.key === k);
      return v ? `${q.label}\n${v}` : "";
    }).filter(Boolean).join("\n\n");
  };

  const runAnalysis = async (instruction = "") => {
    const text = getInputText();
    if (!text.trim() || text.trim().length < 40) return;
    setPhase("analysing");
    setAnalysisProgress([]);

    // ── MULTI-PASS DEEP DIVE ──────────────────────────────────────────────────
    // Each pass targets one module's exact schema. The full document is passed
    // fresh each time so the model attends to the whole text, not a summary.
    // Passes run sequentially; the progress bar advances after each completes.

    const docContext = `DOCUMENT:\n===\n${text}\n===\n` +
      (instruction ? `\nANALYSIS FOCUS INSTRUCTION: ${instruction}\nApply the above instruction to every pass.\n` : "");
    const tick = (id) => setAnalysisProgress(p => [...p, id]);
    const merged = {};

    const runPass = (passPrompt) => new Promise(resolve => {
      call(passPrompt, (r) => {
        if (r && r._raw) {
          try { resolve(JSON.parse(r._raw.replace(/```json|```/g,"").trim())); }
          catch(e) { resolve({}); }
        } else if (r && !r.error) {
          resolve(r);
        } else {
          resolve({});
        }
      });
    });

    // ── PASS 1: DECISION FRAME ────────────────────────────────────────────────
    const p1 = await runPass(
      "You are a senior DQ expert. Extract the decision frame from this document. " +
      "Be specific -- use real names, numbers, and language from the document. Never invent facts. " +
      "If a field cannot be found, use null. Distinguish: extracted (verbatim from doc) vs inferred (reasonably implied).\n\n" +
      docContext +
      'Return ONLY JSON: {"projectName":"short name","executiveSummary":"2-3 sentence DQ-lens summary",' +
      '"frame":{"decisionStatement":"open question: How should / What is the best...","context":"business context","background":"history","trigger":"what precipitated this now",' +
      '"scopeIn":"what is in scope","scopeOut":"what is out of scope","deadline":"deadline if stated","owner":"decision owner if named",' +
      '"constraints":"hard constraints","successCriteria":"what good looks like","urgency":"High|Medium|Low","importance":"High|Medium|Low",' +
      '"confidence":"high|medium|low","confidenceNote":"why"},' +
      '"dqObservations":["DQ observation about frame quality"],"weakestLink":"weakest DQ element","recommendedFirstStep":"most important next action"}'
    );
    Object.assign(merged, p1);
    tick("frame");

    // ── PASS 2: ISSUES (general -- risks, opportunities, constraints) ──────────
    const p2 = await runPass(
      "You are a DQ expert. Extract all issues from this document: risks, opportunities, constraints, operational concerns, financial concerns, strategic concerns, regulatory concerns, dependencies. " +
      "DO NOT include brutal truths or information gaps in this pass -- those are separate. " +
      "For each issue: cite the exact phrase or sentence that led to this inference in 'source'. " +
      "Categorise precisely. Generate 8-15 issues.\n\n" +
      docContext +
      'Return ONLY JSON: {"issues":[{"text":"specific actionable issue","category":"uncertainty-external|uncertainty-internal|opportunity|constraint|stakeholder-concern|focus-decision|assumption","severity":"Critical|High|Medium|Low","confidence":"high|medium|low","source":"quote or phrase from document that drives this"}]}'
    );
    if (p2.issues) merged.issues = p2.issues;
    tick("issues");

    // ── PASS 3: BRUTAL TRUTHS + INFORMATION GAPS ─────────────────────────────
    const p3 = await runPass(
      "You are a DQ facilitator specialising in brutal honesty. From this document:\n" +
      "BRUTAL TRUTHS: Things that are implied but not being said directly. Uncomfortable facts the team may be avoiding. Unspoken tensions. Things everyone knows but no one has written down. Mark with isBrutalTruth:true.\n" +
      "INFORMATION GAPS: Things that are unknown, uncertain, or missing that would materially affect the decision. Missing data, unvalidated assumptions, untested market appetite, unresolved regulatory positions. Mark with isInfoGap:true.\n" +
      "Be specific -- use names and numbers from the document. Generate 4-8 brutal truths and 4-8 information gaps.\n\n" +
      docContext +
      'Return ONLY JSON: {"brutalTruths":[{"text":"the brutal truth stated plainly","severity":"Critical|High|Medium","source":"what in the document implies this"}],' +
      '"informationGaps":[{"text":"the specific gap -- what is unknown","severity":"Critical|High|Medium","decisionImpact":"how this affects the decision","source":"what in the document reveals this gap"}]}'
    );
    if (p3.brutalTruths) merged.brutalTruths = p3.brutalTruths;
    if (p3.informationGaps) merged.informationGaps = p3.informationGaps;
    tick("brutalTruths");
    tick("infoGaps");

    // ── PASS 4: DECISION HIERARCHY + CRITERIA ────────────────────────────────
    const p4 = await runPass(
      "You are a DQ expert. Extract the decision hierarchy and evaluation criteria from this document.\n" +
      "DECISIONS: Identify all sub-decisions. Classify each: focus (in-scope, must be made), given (already decided/locked), deferred (depends on focus decisions), tactical (operational detail). Each focus decision needs 2-4 choices.\n" +
      "CRITERIA: What dimensions would a team use to evaluate the strategic options? Extract from stated objectives, constraints, and trade-offs in the document. 4-7 criteria.\n\n" +
      docContext +
      'Return ONLY JSON: {"decisions":[{"label":"decision label","choices":["choice A","choice B","choice C"],"tier":"focus|given|deferred|tactical","owner":"owner if named","rationale":"why this tier","confidence":"high|medium|low"}],' +
      '"criteria":[{"label":"criterion name","type":"financial|strategic|operational|risk|commercial|technical","weight":"high|medium|low","description":"what this measures","confidence":"high|medium|low"}]}'
    );
    if (p4.decisions) merged.decisions = p4.decisions;
    if (p4.criteria) merged.criteria = p4.criteria;
    tick("hierarchy");
    tick("criteria");

    // ── PASS 5: STRATEGIES ────────────────────────────────────────────────────
    const p5 = await runPass(
      "You are a DQ strategist. Extract or infer the strategic alternatives from this document. " +
      "Each strategy must be genuinely distinct -- different underlying logic, not just different names for the same approach. " +
      "If strategies are not explicitly named, infer them from the options, alternatives, or paths described. Include a status quo / do nothing if relevant. " +
      "2-5 strategies maximum.\n\n" +
      docContext +
      'Return ONLY JSON: {"strategies":[{"name":"Strategy name","description":"one sentence -- what this strategy does and how it differs from others","objective":"what this strategy is trying to achieve","keyAssumption":"the single most important assumption this strategy depends on","confidence":"high|medium|low","isInferred":true}]}'
    );
    if (p5.strategies) merged.strategies = p5.strategies;
    tick("strategy");

    // ── PASS 6: STAKEHOLDERS ──────────────────────────────────────────────────
    const p6 = await runPass(
      "You are a DQ stakeholder analyst. Extract all stakeholders from this document -- individuals, organisations, groups, regulators, partners, internal functions. " +
      "For each: assess their alignment based on what the document says or implies. " +
      "Distinguish: stated (document explicitly describes their position) vs inferred (implied from context).\n\n" +
      docContext +
      'Return ONLY JSON: {"stakeholders":[{"name":"stakeholder name","role":"their role in this decision","influence":"High|Medium|Low","alignment":"champion|neutral|skeptic|blocker","primaryConcern":"what they care about most","mustAlign":true,"confidence":"high|medium|low","isInferred":false}]}'
    );
    if (p6.stakeholders) merged.stakeholders = p6.stakeholders;
    tick("stakeholders");

    // ── PASS 7: UNCERTAINTIES + GAME THEORY SIGNALS ──────────────────────────
    const p7 = await runPass(
      "You are a DQ analyst and game theory expert. From this document:\n\n" +
      "UNCERTAINTIES: The key unknowns that would materially affect which option is best. Different from information gaps -- these are irreducible uncertainties (future states of the world, competitor behaviour, regulatory outcomes). " +
      "These will seed the Scenario Planning and Value of Information modules. 4-8 uncertainties.\n\n" +
      "GAME THEORY: Does this decision involve strategic interaction with other players who have their own objectives and will respond to your moves? " +
      "Identify: the game type (Competitive, Coordination, Collaboration, Sequential, Negotiation, Deterrence, Coalition, Bidding), the key players and their moves, the most important strategic dynamic. " +
      "Only flag if there are genuine strategic interactions -- not every decision is a game theory problem.\n\n" +
      docContext +
      'Return ONLY JSON: {"uncertainties":[{"label":"uncertainty label","description":"what is uncertain and why it matters","decisionImpact":"how this changes which option is best","resolvable":"yes|no|partially","resolutionPath":"how you could find out, if at all","confidence":"high|medium|low"}],' +
      '"gameTheorySignals":{"hasStrategicInteraction":true,"gameType":"Competitive|Coordination|Collaboration|Sequential|Negotiation|Deterrence|Coalition|Bidding|None",' +
      '"rationale":"why this game type","keyPlayers":[{"name":"player","objective":"what they want","keyMove":"their most important available action"}],' +
      '"mostImportantDynamic":"the single most important strategic dynamic to understand","recommendGameTheoryAnalysis":true}}'
    );
    if (p7.uncertainties) merged.uncertainties = p7.uncertainties;
    if (p7.gameTheorySignals) merged.gameTheorySignals = p7.gameTheorySignals;
    tick("uncertainties");
    tick("gameTheory");

    // ── PASS 8: INFLUENCE MAP ────────────────────────────────────────────────
    const p8 = await runPass(
      "You are a systems thinker building a causal influence map. From this document, identify all key variables that influence the decision outcome. " +
      "NODE TYPES: 'decision' (choices being made), 'uncertainty' (unknowns that affect outcomes), 'value' (what stakeholders care about), " +
      "'constraint' (hard limits), 'external' (outside forces), 'objective' (goals). " +
      "EDGES: directional relationships between nodes with strength (strong/moderate/weak) and direction of influence. " +
      "Be specific -- use real names from the document. 8-16 nodes, 10-20 edges." +
      docContext +
      'Return ONLY JSON: {"influenceNodes":[{"id":"n1","label":"node name","type":"decision|uncertainty|value|constraint|external|objective","description":"what this represents","confidence":"high|medium|low","source":"from document"}],' +
      '"influenceEdges":[{"source":"n1","target":"n2","label":"how n1 influences n2","strength":"strong|moderate|weak","confidence":"high|medium|low"}]}'
    );
    if (p8.influenceNodes) merged.influenceNodes = p8.influenceNodes;
    if (p8.influenceEdges) merged.influenceEdges = p8.influenceEdges;
    tick("influence");

    // ── PASS 9: SCENARIO PLANNING ─────────────────────────────────────────────
    const p9 = await runPass(
      "You are a scenario planning strategist. From this document, design a scenario framework. " +
      "Identify the 2 most decision-critical uncertainties as scenario axes. " +
      "Construct 4 coherent scenario narratives from the 2x2 matrix. " +
      "For each scenario: name it, describe the world it depicts, and assess which strategy performs best in it. " +
      "Also identify early warning indicators -- observable signals that would tell you which scenario is materialising." +
      docContext +
      'Return ONLY JSON: {"scenarioAxes":{"axis1":{"label":"axis 1 label","low":"low end description","high":"high end description"},' +
      '"axis2":{"label":"axis 2 label","low":"low end description","high":"high end description"}},' +
      '"scenarios":[{"name":"scenario name","quadrant":"high-high|high-low|low-high|low-low","narrative":"3-4 sentence description of this world",' +
      '"bestStrategy":"which strategy performs best here and why","earlyWarnings":["observable signal that this scenario is developing"]}],' +
      '"mostDangerousScenario":"name and why it is most threatening","robustStrategy":"which strategy performs acceptably across the most scenarios"}'
    );
    if (p9.scenarioAxes) merged.scenarioAxes = p9.scenarioAxes;
    if (p9.scenarios) merged.scenarioNarratives = p9.scenarios;
    if (p9.mostDangerousScenario) merged.mostDangerousScenario = p9.mostDangerousScenario;
    if (p9.robustStrategy) merged.robustStrategy = p9.robustStrategy;
    tick("scenarios");

    // ── PASS 10: VALUE OF INFORMATION ────────────────────────────────────────
    const p10 = await runPass(
      "You are a Value of Information analyst. From this document, identify which uncertainties are worth resolving before committing to a decision. " +
      "Apply the three VoI questions to each: (1) Would knowing this change the decision? (2) Can we find out before we must decide? (3) Is the cost/delay of finding out less than the risk of not knowing? " +
      "Classify each as: do_now (resolve before committing), do_later (useful but not blocking), conditional (only if a trigger occurs), do_not_do (not worth the cost). " +
      "Suggest a specific information-gathering action for each do_now item." +
      docContext +
      'Return ONLY JSON: {"voiItems":[{"label":"uncertainty label","description":"what is unknown","wouldChangeDecision":true,"canResolveInTime":true,"worthCost":true,' +
      '"classification":"do_now|do_later|conditional|do_not_do","action":"specific study or action to gather this information","costEstimate":"Low|Medium|High",' +
      '"timeToLearn":"e.g. 4-6 weeks","decisionPivot":"if resolved favourably: stay with X; if adversely: switch to Y","confidence":"high|medium|low"}],' +
      '"voiSummary":"executive summary of VoI findings"}'
    );
    if (p10.voiItems) merged.voiItems = p10.voiItems;
    if (p10.voiSummary) merged.voiSummary = p10.voiSummary;
    tick("voi");

    // ── PASS 11: RISK TIMELINE ────────────────────────────────────────────────
    const p11 = await runPass(
      "You are a decision risk analyst. From this document, build a risk timeline showing: " +
      "key risk events, decision gates (points where the team must decide or pivot), milestones, and implementation checkpoints. " +
      "For each event: estimate timing relative to now (months from today), type, severity, trigger, and mitigation. " +
      "Decision gates are the most important -- identify the conditions that must be met to proceed at each gate." +
      docContext +
      'Return ONLY JSON: {"timelineEvents":[{"title":"event title","type":"decision_gate|risk_event|milestone|implementation|review","timing":6,' +
      '"timingLabel":"e.g. Month 6 from FID","severity":"Critical|High|Medium|Low","description":"what happens at this point",' +
      '"trigger":"what causes this event","mitigation":"how to reduce the risk or prepare for this gate",' +
      '"gateCondition":"for decision gates: what must be true to proceed","owner":"owner if named","confidence":"high|medium|low","source":"from document"}],' +
      '"criticalPath":"description of the most time-sensitive sequence of events","longestLeadTime":"the constraint that takes longest to resolve"}'
    );
    if (p11.timelineEvents) merged.timelineEvents = p11.timelineEvents;
    if (p11.criticalPath) merged.criticalPath = p11.criticalPath;
    tick("timeline");

    // ── PASS 12: DQ SCORECARD + VALIDATION FLAGS ──────────────────────────────
    const p12 = await runPass(
      "You are a DQ auditor. Evaluate this document against the six Decision Quality elements and identify all validation flags. " +
      "DQ ELEMENTS (score 0-100 each based on what the document reveals): " +
      "Frame (Is the right decision being addressed?), Alternatives (Are genuinely distinct options present?), " +
      "Information (Is key data present and reliable?), Values (Are criteria and trade-offs explicit?), " +
      "Reasoning (Is the logic connecting evidence to conclusions sound?), Commitment (Is stakeholder alignment sufficient?). " +
      "VALIDATION FLAGS: check for all 16 flag types from the brief." +
      docContext +
      'Return ONLY JSON: {"dqScores":{"frame":0,"alternatives":0,"information":0,"values":0,"reasoning":0,"commitment":0},' +
      '"dqNarrative":"2-3 sentence assessment of overall decision quality in the document",' +
      '"readinessVerdict":"not_ready|conditional|ready",' +
      '"validationFlags":[{"type":"unclear_decision|missing_owner|missing_objectives|unclear_scope|weak_alternatives|no_uncertainties|unsupported_assumptions|stakeholder_gaps|missing_timelines|strategy_objective_mismatch|unresolved_risks|false_precision|insufficient_evidence|possible_bias|missing_game_theory_players|missing_scenario_drivers",' +
      '"severity":"critical|warning|info","message":"specific observation from the document","suggestion":"what to do about it"}],' +
      '"crossModuleInsights":{"contradictions":["contradiction found across sections"],"framingDriftRisks":["ways the framing may drift from intent"],' +
      '"orphanRisks":["risks with no mitigation or strategy linkage"],"missingDownstreamAnalysis":["modules that should be run but are absent from the document"],' +
      '"strategicTensions":["genuine trade-offs or tensions the document contains"]}}'
    );
    if (p12.dqScores) merged.dqScores = p12.dqScores;
    if (p12.dqNarrative) merged.dqNarrative = p12.dqNarrative;
    if (p12.readinessVerdict) merged.readinessVerdict = p12.readinessVerdict;
    if (p12.validationFlags) merged.validationFlags = p12.validationFlags;
    if (p12.crossModuleInsights) merged.crossModuleInsights = p12.crossModuleInsights;
    tick("scorecard");
    tick("crossModule");

    // ── DONE ──────────────────────────────────────────────────────────────────
    setAnalysisProgress(ANALYSIS_STEPS.map(s => s.id));
    setDraft(merged);
    setAccepted({
      frame:true, issues:true, brutalTruths:true, infoGaps:true,
      decisions:true, criteria:true, strategies:true,
      stakeholders:true, uncertainties:true, gameTheory:false,
      influence:true, scenarios:true, voi:true, timeline:true,
      scorecard:true, crossModule:true,
    });
    setActiveReviewTab("frame");
    setTimeout(() => setPhase("review"), 400);
  };

  const applyDraft = () => { if (draft) onComplete(draft, accepted); };
  const confVar = c => c==="high"?"green":c==="medium"?"warn":"danger";

  const sharedStyles = `
    @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;500;600;700&family=Libre+Baskerville:ital,wght@0,700;1,400&display=swap');
    * { box-sizing:border-box; }
    @keyframes spin{to{transform:rotate(360deg)}}
    @keyframes fadeUp{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
    @keyframes fadeIn{from{opacity:0}to{opacity:1}}
    ::-webkit-scrollbar{width:5px}
    ::-webkit-scrollbar-thumb{background:#252b3b;border-radius:3px}
  `;

  const overlay = { position:"fixed", inset:0, background:DS.chrome, zIndex:200,
    fontFamily:"'IBM Plex Sans','Helvetica Neue',sans-serif", color:DS.textPri };

  // ── LANDING ──
  if (phase === "landing") return (
    <div style={{ ...overlay, display:"flex", alignItems:"center", justifyContent:"center",
      background:"linear-gradient(135deg,#0d1117 0%,#0f172a 50%,#0d1117 100%)" }}>
      <style>{`
        @keyframes fadeUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:none}}
        @keyframes shimmer{0%,100%{opacity:.4}50%{opacity:1}}
        .qs-card:hover { transform:translateY(-3px)!important; box-shadow:0 16px 48px rgba(0,0,0,.4)!important; }
        .qs-card:hover .qs-icon { transform:scale(1.1); }
        .qs-card { transition:transform .2s ease, box-shadow .2s ease!important; }
        .qs-icon { transition:transform .2s ease; }
      `}</style>

      <div style={{ width:"100%", maxWidth:820, padding:"40px 32px", animation:"fadeUp .5s ease" }}>

        {/* Logo */}
        <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:48 }}>
          <div style={{ width:36, height:36, borderRadius:9,
            background:"linear-gradient(135deg,#2563eb,#7c3aed)",
            display:"flex", alignItems:"center", justifyContent:"center",
            boxShadow:"0 4px 16px rgba(37,99,235,.4)" }}>
            <svg width="18" height="18" viewBox="0 0 24 24" fill="none"
              stroke="#fff" strokeWidth="2.5" strokeLinecap="round">
              <polygon points="12,2 22,8.5 22,15.5 12,22 2,15.5 2,8.5"/>
              <line x1="12" y1="2" x2="12" y2="22"/>
              <line x1="2" y1="8.5" x2="22" y2="8.5"/>
              <line x1="2" y1="15.5" x2="22" y2="15.5"/>
            </svg>
          </div>
          <div>
            <div style={{ fontSize:16, fontWeight:700, color:"#f1f5f9", letterSpacing:-.2 }}>Vantage DQ</div>
            <div style={{ fontSize:9, color:"#475569", letterSpacing:1.8, textTransform:"uppercase" }}>
              Decision Quality Platform
            </div>
          </div>
        </div>

        {/* Headline */}
        <div style={{ marginBottom:48 }}>
          <div style={{ fontFamily:"'Libre Baskerville',Georgia,serif",
            fontSize:42, fontWeight:700, color:"#f1f5f9",
            lineHeight:1.1, letterSpacing:-.5, marginBottom:16 }}>
            Make better decisions.<br/>
            <span style={{ background:"linear-gradient(90deg,#3b82f6,#7c3aed)",
              WebkitBackgroundClip:"text", WebkitTextFillColor:"transparent" }}>
              With rigour.
            </span>
          </div>
          <div style={{ fontSize:15, color:"#64748b", lineHeight:1.7, maxWidth:540 }}>
            A structured Decision Quality environment for teams making high-stakes decisions
            under uncertainty.
          </div>
        </div>

        {/* 4 option cards */}
        <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:14, marginBottom:32 }}>
          {[
            {
              mode:"paste",
              icon:"📄",
              label:"AI Deep Dive",
              sublabel:"Fastest start",
              desc:"Paste a brief, memo, board paper or any text -- AI structures your complete decision frame in seconds.",
              color:"#3b82f6",
              gradient:"linear-gradient(135deg,#1e3a5f,#1e40af)",
              action:()=>{ setInputMode("paste"); setPhase("input"); },
              featured:true,
            },
            {
              mode:"guided",
              icon:"🗂",
              label:"Guided Questions",
              sublabel:"No document needed",
              desc:"Answer 5 DQ-specific questions about your decision -- frame, trigger, options, uncertainty, and success criteria. The AI builds your complete decision structure from your answers.",
              color:"#7c3aed",
              gradient:"linear-gradient(135deg,#2e1065,#5b21b6)",
              action:()=>{ setInputMode("guided"); setPhase("input"); },
              featured:false,
            },
            {
              mode:"clean",
              icon:"◌",
              label:"Start Clean",
              sublabel:"Blank workspace",
              desc:"Begin with a completely blank workspace. Your decision, your frame, your way.",
              color:"#059669",
              gradient:"linear-gradient(135deg,#064e3b,#065f46)",
              action:()=>onSkip("clean"),
              featured:false,
            },
            {
              mode:"example",
              icon:"🌏",
              label:"Load Example",
              sublabel:"APAC market entry",
              desc:"Explore a pre-built decision to see how Vantage DQ works end-to-end before you start.",
              color:"#d97706",
              gradient:"linear-gradient(135deg,#451a03,#78350f)",
              action:()=>onSkip("example"),
              featured:false,
            },
          ].map((opt,i)=>(
            <button key={opt.mode} className="qs-card" onClick={opt.action}
              style={{ padding:"24px 26px", textAlign:"left",
                background:opt.featured
                  ? "linear-gradient(135deg,#1e3a5f 0%,#1e2d45 100%)"
                  : "rgba(255,255,255,.04)",
                border:`1.5px solid ${opt.featured?"#3b82f680":"rgba(255,255,255,.08)"}`,
                borderRadius:14, cursor:"pointer",
                fontFamily:"inherit",
                position:"relative", overflow:"hidden",
                boxShadow:opt.featured?"0 8px 32px rgba(37,99,235,.25)":"none" }}>

              {/* Subtle gradient top border */}
              <div style={{ position:"absolute", top:0, left:0, right:0, height:2,
                background:opt.gradient, opacity:.8 }}/>

              {/* Featured badge */}
              {opt.featured && (
                <div style={{ position:"absolute", top:12, right:12,
                  fontSize:8, fontWeight:700, letterSpacing:.5,
                  textTransform:"uppercase", padding:"2px 8px",
                  background:"rgba(59,130,246,.2)",
                  border:"1px solid rgba(59,130,246,.3)",
                  borderRadius:4, color:"#93c5fd" }}>
                  Recommended
                </div>
              )}

              {/* Icon */}
              <div className="qs-icon" style={{ fontSize:28, marginBottom:14,
                display:"inline-block" }}>{opt.icon}</div>

              {/* Labels */}
              <div style={{ display:"flex", alignItems:"baseline", gap:8, marginBottom:6 }}>
                <div style={{ fontSize:16, fontWeight:700, color:"#f1f5f9",
                  letterSpacing:-.2 }}>{opt.label}</div>
                <div style={{ fontSize:10, color:opt.color, fontWeight:600 }}>
                  {opt.sublabel}
                </div>
              </div>

              {/* Description */}
              <div style={{ fontSize:12, color:"#64748b", lineHeight:1.6 }}>
                {opt.desc}
              </div>

              {/* Arrow */}
              <div style={{ position:"absolute", bottom:20, right:20,
                fontSize:14, color:opt.color, opacity:.7 }}>→</div>
            </button>
          ))}
        </div>

        {/* Footer */}
        <div style={{ display:"flex", alignItems:"center", justifyContent:"center",
          gap:24 }}>
          <div style={{ fontSize:11, color:"#334155" }}>
            11 modules · AI-powered · Built for high-stakes decisions
          </div>
        </div>
      </div>
    </div>
  );

  // ── INPUT  ──
  if (phase === "input") return (
    <div style={{ ...overlay, display:"flex", flexDirection:"column" }}>
      <style>{sharedStyles}</style>

      <div style={{ padding:"13px 24px", borderBottom:`1px solid ${DS.border}`,
        display:"flex", alignItems:"center", gap:14, flexShrink:0, background:DS.chromeAlt }}>
        <button onClick={()=>setPhase("landing")}
          style={{ background:"none", border:"1px solid "+DS.border, borderRadius:5, cursor:"pointer",
            color:DS.textSec, fontSize:11, fontWeight:700, fontFamily:"inherit",
            padding:"4px 10px", display:"flex", alignItems:"center", gap:4, flexShrink:0 }}>
          ← Back
        </button>
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          <div style={{ width:26, height:26, borderRadius:5, background:DS.accent,
            display:"flex", alignItems:"center", justifyContent:"center" }}>
            <Svg path={ICONS.spark} size={13} color="#fff"/>
          </div>
          <span style={{ fontSize:13, fontWeight:700, color:DS.textPri }}>AI Deep Dive</span>
        </div>
        <div style={{ display:"flex", gap:5 }}>
          {[{id:"paste",label:"Paste Text"},{id:"guided",label:"5 Questions"}].map(m=>(
            <button key={m.id} onClick={()=>setInputMode(m.id)}
              style={{ padding:"5px 13px", fontSize:11, fontWeight:700, fontFamily:"inherit",
                cursor:"pointer", border:`1px solid ${inputMode===m.id?DS.accent:DS.border}`,
                borderRadius:5, background:inputMode===m.id?DS.accent:"transparent",
                color:inputMode===m.id?"#fff":DS.textTer, transition:"all .12s" }}>
              {m.label}
            </button>
          ))}
        </div>
        <button onClick={()=>setPhase("landing")}
          style={{ marginLeft:"auto", background:"none", border:"none", cursor:"pointer",
            color:DS.textTer, display:"flex", alignItems:"center", gap:5, fontFamily:"inherit", fontSize:12 }}>
          <Svg path={ICONS.x} size={14} color={DS.textTer}/> Back
        </button>
      </div>

      <div style={{ flex:1, display:"flex", overflow:"hidden" }}>
        <div style={{ flex:1, overflowY:"auto", padding:"32px 40px", maxWidth:840, margin:"0 auto", width:"100%" }}>

          {inputMode === "paste" && (
            <div style={{ animation:"fadeUp .25s ease" }}>
              <div style={{ marginBottom:20 }}>
                <div style={{ fontFamily:"'Libre Baskerville',Georgia,serif", fontSize:22,
                  fontWeight:700, color:DS.textPri, marginBottom:8 }}>Paste your problem context</div>
                <div style={{ fontSize:13, color:DS.textSec, lineHeight:1.6 }}>
                  Any format -- board paper, strategy brief, email thread, rough notes. Min 40 characters.
                </div>
              </div>

              <div
                onDragOver={e=>{ e.preventDefault(); setDragOver(true); }}
                onDragLeave={()=>setDragOver(false)}
                onDrop={e=>{
                  e.preventDefault(); setDragOver(false);
                  const file = e.dataTransfer.files[0];
                  if (file?.type==="text/plain") {
                    const reader = new FileReader();
                    reader.onload = ev => setRawText(ev.target.result);
                    reader.readAsText(file);
                  }
                }}
                style={{ marginBottom:12, padding:"11px 16px",
                  background:dragOver?"rgba(37,99,235,.08)":"rgba(255,255,255,.02)",
                  border:`1.5px dashed ${dragOver?DS.accent:DS.border}`,
                  borderRadius:8, textAlign:"center", transition:"all .15s" }}>
                <div style={{ fontSize:11, color:DS.textTer }}>Drop a .txt file here, or paste below</div>
              </div>

              <textarea value={rawText} onChange={e=>setRawText(e.target.value)} rows={18}
                placeholder={`Paste your decision context here…\n\nExample:\n"Our business faces increasing competition in APAC. The board has asked us to evaluate market entry options and present a recommendation by Q2. Budget ceiling is $25M for Year 1. We need to balance speed to market with capital efficiency. Options under consideration include a direct subsidiary, strategic partnership, or acquiring a local player…"`}
                style={{ width:"100%", padding:"16px 18px", fontSize:13, fontFamily:"inherit",
                  background:DS.chromeMid, border:`1px solid ${DS.border}`, borderRadius:8,
                  color:DS.textSec, outline:"none", resize:"vertical", lineHeight:1.7,
                  boxSizing:"border-box" }}
                onFocusCapture={e=>e.target.style.borderColor=DS.accent}
                onBlurCapture={e=>e.target.style.borderColor=DS.border}/>

              <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginTop:14 }}>
                <span style={{ fontSize:11, color:rawText.length<40?DS.danger:DS.textTer }}>
                  {rawText.length} chars {rawText.length<40?"-- min 40 required":"✓"}
                </span>
                <Btn variant="primary" icon="spark" size="lg" onClick={runAnalysis}
                  disabled={busy||rawText.trim().length<40}>
                  Run Deep Dive Analysis
                </Btn>
              </div>
            </div>
          )}

          {inputMode === "guided" && (
            <div style={{ animation:"fadeUp .25s ease" }}>
              <div style={{ marginBottom:24 }}>
                <div style={{ fontFamily:"'Libre Baskerville',Georgia,serif", fontSize:22,
                  fontWeight:700, color:DS.textPri, marginBottom:8 }}>Five DQ-focused questions</div>
                <div style={{ fontSize:13, color:DS.textSec, lineHeight:1.6 }}>
                  Be specific -- the more concrete your answers, the sharper the AI output. Answer at least 2 questions. Rough notes are fine.
                </div>
              </div>

              {GUIDED_QUESTIONS.map((q, i) => (
                <div key={q.key} style={{ marginBottom:20 }}>
                  <div style={{ display:"flex", alignItems:"baseline", gap:10, marginBottom:8 }}>
                    <span style={{ width:22, height:22, borderRadius:5, background:DS.accent,
                      display:"inline-flex", alignItems:"center", justifyContent:"center",
                      fontSize:11, fontWeight:700, color:"#fff", flexShrink:0 }}>{i+1}</span>
                    <label style={{ fontSize:13, fontWeight:700, color:DS.textPri }}>{q.label}</label>
                  </div>
                  <textarea value={guidedAnswers[q.key]} rows={4}
                    onChange={e=>setGuidedAnswers(a=>({...a,[q.key]:e.target.value}))}
                    placeholder={q.placeholder}
                    style={{ width:"100%", padding:"11px 14px", fontSize:12, fontFamily:"inherit",
                      background:DS.chromeMid, border:`1px solid ${DS.border}`, borderRadius:7,
                      color:DS.textSec, outline:"none", resize:"vertical", lineHeight:1.6,
                      boxSizing:"border-box" }}
                    onFocusCapture={e=>e.target.style.borderColor=DS.accent}
                    onBlurCapture={e=>e.target.style.borderColor=DS.border}/>
                </div>
              ))}

              <div style={{ display:"flex", justifyContent:"flex-end" }}>
                <Btn variant="primary" icon="spark" size="lg" onClick={runAnalysis}
                  disabled={busy || Object.values(guidedAnswers).filter(v=>v.trim().length>10).length < 2}>
                  Run Deep Dive Analysis
                </Btn>
              </div>
            </div>
          )}
        </div>

        {/* Tips sidebar */}
        <div style={{ width:260, borderLeft:`1px solid ${DS.border}`, padding:"24px 20px",
          overflowY:"auto", flexShrink:0 }}>
          <div style={{ fontSize:10, fontWeight:700, color:DS.textTer, letterSpacing:.8,
            textTransform:"uppercase", marginBottom:16 }}>What Vantage extracts</div>
          {[
            { icon:"◎", label:"Decision Frame", desc:"Statement, context, scope, owner, constraints, success criteria" },
            { icon:"◈", label:"8-12 Issues", desc:"Tagged by type and severity across stakeholder perspectives" },
            { icon:"◧", label:"Decision Hierarchy", desc:"Decisions across all 5 tiers -- Given, Focus, Tactical, Deferred, Dependencies" },
            { icon:"◫", label:"Decision Criteria", desc:"What the organisation values -- how strategies will be judged" },
            { icon:"⊞", label:"2-4 Strategies", desc:"Initial coherent directions as a starting scaffold" },
          ].map(item => (
            <div key={item.icon} style={{ marginBottom:14, display:"flex", gap:10 }}>
              <span style={{ fontSize:14, flexShrink:0 }}>{item.icon}</span>
              <div>
                <div style={{ fontSize:11, fontWeight:700, color:DS.textSec, marginBottom:2 }}>{item.label}</div>
                <div style={{ fontSize:10, color:DS.textTer, lineHeight:1.5 }}>{item.desc}</div>
              </div>
            </div>
          ))}
          <div style={{ marginTop:16, padding:"11px 13px", background:DS.chromeMid,
            border:`1px solid ${DS.border}`, borderRadius:7 }}>
            <div style={{ fontSize:11, fontWeight:700, color:DS.accent, marginBottom:5 }}>This is a first draft</div>
            <div style={{ fontSize:11, color:DS.textTer, lineHeight:1.55 }}>
              Everything Vantage produces is a starting point. DQ quality comes from the team's process -- not the AI output.
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  // ── ANALYSING ──
  if (phase === "analysing") return (
    <div style={{ ...overlay, display:"flex", alignItems:"center", justifyContent:"center" }}>
      <style>{sharedStyles}</style>
      <div style={{ width:480, textAlign:"center" }}>
        <div style={{ width:52, height:52, margin:"0 auto 24px", borderRadius:"50%",
          border:`3px solid ${DS.border}`, borderTop:`3px solid ${DS.accent}`,
          animation:"spin 1s linear infinite" }}/>
        <div style={{ fontFamily:"'Libre Baskerville',Georgia,serif", fontSize:22,
          fontWeight:700, color:DS.textPri, marginBottom:8 }}>Applying Decision Quality methodology</div>
        <div style={{ fontSize:13, color:DS.textSec, marginBottom:36, lineHeight:1.6 }}>
          Analysing your context across all five DQ modules…
        </div>
        <div style={{ display:"flex", flexDirection:"column", gap:8, textAlign:"left" }}>
          {ANALYSIS_STEPS.map((step, i) => {
            const done = analysisProgress.includes(step.id);
            const active = !done && analysisProgress.length === i;
            return (
              <div key={step.id} style={{ display:"flex", alignItems:"center", gap:12,
                padding:"10px 16px", borderRadius:8,
                background:done?"rgba(5,150,105,.08)":active?DS.chromeSub:DS.chromeMid,
                border:`1px solid ${done?DS.successLine:active?DS.accent:DS.border}40`,
                opacity:done||active?1:0.4, transition:"all .3s" }}>
                <div style={{ width:22, height:22, borderRadius:5, flexShrink:0,
                  background:done?DS.success:active?DS.accent:DS.chromeSub,
                  display:"flex", alignItems:"center", justifyContent:"center" }}>
                  {done
                    ? <Svg path={ICONS.check} size={12} color="#fff" sw={2.5}/>
                    : active
                      ? <div style={{ width:10,height:10,borderRadius:"50%",border:"2px solid #fff",borderTop:"2px solid transparent",animation:"spin .8s linear infinite" }}/>
                      : <span style={{ color:DS.textTer, fontSize:9 }}>{i+1}</span>
                  }
                </div>
                <div style={{ flex:1 }}>
                  <div style={{ fontSize:12, fontWeight:600, color:done||active?DS.textPri:DS.textTer }}>
                    {step.label}
                  </div>
                  <div style={{ fontSize:10, color:DS.textTer }}>→ {step.module}</div>
                </div>
                {done && <span style={{ fontSize:11, color:DS.success }}>✓</span>}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );

  // ── REVIEW ──
  if (phase === "review" && draft) {
    const sections = [
      { key:"frame",        label:"Problem Definition",  count:null,                                          icon:"◎" },
      { key:"issues",       label:"Issues",              count:draft.issues?.length,                          icon:"◈" },
      { key:"brutalTruths", label:"Brutal Truths",       count:draft.brutalTruths?.length,                    icon:"⚑" },
      { key:"infoGaps",     label:"Information Gaps",    count:draft.informationGaps?.length,                 icon:"◎" },
      { key:"decisions",    label:"Decision Hierarchy",  count:draft.decisions?.length,                       icon:"◧" },
      { key:"criteria",     label:"Criteria",            count:draft.criteria?.length,                        icon:"◫" },
      { key:"strategies",   label:"Strategies",          count:draft.strategies?.length,                      icon:"⊞" },
      { key:"stakeholders", label:"Stakeholders",        count:draft.stakeholders?.length,                    icon:"◉" },
      { key:"uncertainties",label:"Uncertainties",       count:draft.uncertainties?.length,                   icon:"◈" },
      { key:"gameTheory",   label:"Game Theory",         count:draft.gameTheorySignals?.hasStrategicInteraction?1:0, icon:"♟" },
      { key:"influence",    label:"Influence Map",       count:draft.influenceNodes?.length,                  icon:"⊕" },
      { key:"scenarios",    label:"Scenarios",           count:draft.scenarioNarratives?.length,              icon:"◈" },
      { key:"voi",          label:"Value of Info",       count:draft.voiItems?.length,                        icon:"◎" },
      { key:"timeline",     label:"Risk Timeline",       count:draft.timelineEvents?.length,                  icon:"⊳" },
      { key:"scorecard",    label:"DQ Scorecard",        count:draft.validationFlags?.length,                 icon:"◉" },
      { key:"crossModule",  label:"Cross-Module",        count:draft.crossModuleInsights?.contradictions?.length, icon:"✦" },
    ];

    return (
      <div style={{ ...overlay, display:"flex", flexDirection:"column" }}>
        <style>{sharedStyles}</style>

        {/* Top bar */}
        <div style={{ padding:"13px 24px", borderBottom:`1px solid ${DS.border}`,
          display:"flex", alignItems:"center", gap:14, flexShrink:0, background:DS.chromeAlt }}>
          <div style={{ width:26, height:26, borderRadius:5, background:DS.success,
            display:"flex", alignItems:"center", justifyContent:"center" }}>
            <Svg path={ICONS.check} size={13} color="#fff" sw={2.5}/>
          </div>
          <div>
            <div style={{ fontSize:13, fontWeight:700, color:DS.textPri }}>First Draft Ready -- {draft.projectName}</div>
            <div style={{ fontSize:11, color:DS.textTer }}>Review what Vantage inferred · toggle sections on/off · load when ready</div>
          </div>
          <div style={{ marginLeft:"auto", display:"flex", gap:8, alignItems:"center" }}>
            <div style={{ display:"flex", gap:6, alignItems:"center" }}>
              <input
                value={rerunInstruction}
                onChange={e=>setRerunInstruction(e.target.value)}
                placeholder="Rerun with instruction, e.g. 'focus on regulatory risks'…"
                style={{ width:280, padding:"5px 10px", fontSize:11, fontFamily:"inherit",
                  background:DS.chromeSub, border:`1px solid ${DS.border}`, borderRadius:6,
                  color:DS.textPri, outline:"none" }}
                onKeyDown={e=>{ if(e.key==="Enter" && rerunInstruction.trim()) {
                  setPhase("analysing");
                  setAnalysisProgress([]);
                  setRerunInstruction("");
                  runAnalysis(rerunInstruction);
                }}}
              />
              {rerunInstruction.trim() && (
                <Btn variant="chrome" size="sm" onClick={()=>{
                  setPhase("analysing");
                  setAnalysisProgress([]);
                  const inst = rerunInstruction;
                  setRerunInstruction("");
                  runAnalysis(inst);
                }}>↺ Rerun</Btn>
              )}
            </div>
            <Btn variant="chrome" onClick={()=>setPhase("input")} size="sm">← Back</Btn>
            <Btn variant="chrome" size="sm" onClick={()=>{
              const html = generateDeepDiveReport(draft);
              const w = window.open("","_blank");
              w.document.write(html);
              w.document.close();
            }}>⬇ Export Report</Btn>
            <Btn variant="primary" icon="check" onClick={applyDraft}>Load Draft →</Btn>
          </div>
        </div>

        <div style={{ flex:1, display:"flex", overflow:"hidden" }}>

          {/* Left sidebar -- summary */}
          <div style={{ width:240, borderRight:`1px solid ${DS.border}`, overflowY:"auto",
            flexShrink:0, padding:"20px 18px" }}>

            {draft.executiveSummary && (
              <div style={{ marginBottom:18, paddingBottom:18, borderBottom:`1px solid ${DS.border}` }}>
                <div style={{ fontSize:9, fontWeight:700, color:DS.textTer, letterSpacing:1,
                  textTransform:"uppercase", marginBottom:8 }}>Executive Summary</div>
                <div style={{ fontSize:11, color:DS.textSec, lineHeight:1.65 }}>{draft.executiveSummary}</div>
              </div>
            )}

            {draft.dqObservations?.length > 0 && (
              <div style={{ marginBottom:18, paddingBottom:18, borderBottom:`1px solid ${DS.border}` }}>
                <div style={{ fontSize:9, fontWeight:700, color:DS.textTer, letterSpacing:1,
                  textTransform:"uppercase", marginBottom:8 }}>DQ Observations</div>
                {draft.dqObservations.map((obs,i) => (
                  <div key={i} style={{ fontSize:11, color:"#fbbf24", lineHeight:1.5, marginBottom:6,
                    paddingLeft:8, borderLeft:`2px solid #f59e0b` }}>{obs}</div>
                ))}
              </div>
            )}

            {draft.weakestLink && (
              <div style={{ marginBottom:18, paddingBottom:18, borderBottom:`1px solid ${DS.border}` }}>
                <div style={{ fontSize:9, fontWeight:700, color:DS.danger, letterSpacing:1,
                  textTransform:"uppercase", marginBottom:6 }}>Weakest DQ Link</div>
                <div style={{ fontSize:11, color:DS.textSec, lineHeight:1.5 }}>{draft.weakestLink}</div>
              </div>
            )}

            {draft.recommendedFirstStep && (
              <div>
                <div style={{ fontSize:9, fontWeight:700, color:DS.success, letterSpacing:1,
                  textTransform:"uppercase", marginBottom:6 }}>First Step</div>
                <div style={{ fontSize:11, color:DS.textSec, lineHeight:1.5 }}>{draft.recommendedFirstStep}</div>
              </div>
            )}
          </div>

          {/* Main review area */}
          <div style={{ flex:1, overflowY:"auto", padding:"20px 28px" }}>

            {/* Section toggles */}
            <div style={{ display:"flex", gap:7, flexWrap:"wrap", marginBottom:22 }}>
              {sections.map(s => (
                <button key={s.key} onClick={()=>setAccepted(a=>({...a,[s.key]:!a[s.key]}))}
                  style={{ display:"flex", alignItems:"center", gap:6, padding:"6px 12px",
                    borderRadius:6, border:`1.5px solid ${accepted[s.key]?DS.accent:DS.border}`,
                    background:accepted[s.key]?DS.chromeSub:DS.chromeMid,
                    cursor:"pointer", fontFamily:"inherit", transition:"all .12s" }}>
                  <span style={{ fontSize:12, fontWeight:700, color:accepted[s.key]?DS.accent:DS.textTer }}>
                    {accepted[s.key]?"✓":"○"} {s.label}
                  </span>
                  {s.count && (
                    <span style={{ fontSize:10, fontWeight:700, padding:"1px 6px", borderRadius:10,
                      background:accepted[s.key]?DS.accent:DS.border,
                      color:accepted[s.key]?"#fff":DS.textTer }}>{s.count}</span>
                  )}
                </button>
              ))}
            </div>

            {/* FRAME */}
            {accepted.frame && draft.frame && (
              <div style={{ marginBottom:16, border:`1px solid ${DS.canvasBdr}`, borderRadius:8,
                overflow:"hidden", background:DS.canvas }}>
                <div style={{ padding:"10px 16px", background:DS.canvasAlt,
                  borderBottom:`1px solid ${DS.canvasBdr}`, display:"flex", alignItems:"center", justifyContent:"space-between" }}>
                  <div style={{ fontSize:12, fontWeight:700, color:DS.ink }}>◎ Problem Definition</div>
                  <Badge variant={confVar(draft.frame.confidence)} size="xs">{draft.frame.confidence} confidence</Badge>
                </div>
                <div style={{ padding:"14px 16px", display:"grid", gridTemplateColumns:"1fr 1fr", gap:12 }}>
                  {[
                    ["Decision Statement", draft.frame.decisionStatement],
                    ["Owner", draft.frame.owner],
                    ["Trigger", draft.frame.trigger],
                    ["Deadline", draft.frame.deadline],
                    ["Scope In", draft.frame.scopeIn],
                    ["Scope Out", draft.frame.scopeOut],
                    ["Constraints", draft.frame.constraints],
                    ["Success Criteria", draft.frame.successCriteria],
                  ].filter(([,v])=>v).map(([label, val]) => (
                    <div key={label}>
                      <div style={{ fontSize:10, fontWeight:700, color:DS.inkTer,
                        letterSpacing:.6, textTransform:"uppercase", marginBottom:3 }}>{label}</div>
                      <div style={{ fontSize:12, color:DS.ink, lineHeight:1.5 }}>{val}</div>
                    </div>
                  ))}
                </div>
                {draft.frame.confidenceNote && (
                  <div style={{ padding:"8px 16px", borderTop:`1px solid ${DS.canvasBdr}`,
                    fontSize:11, color:DS.inkTer, fontStyle:"italic" }}>
                    ℹ {draft.frame.confidenceNote}
                  </div>
                )}
              </div>
            )}

            {/* ISSUES */}
            {accepted.issues && draft.issues?.length > 0 && (
              <div style={{ marginBottom:16, border:`1px solid ${DS.canvasBdr}`, borderRadius:8,
                overflow:"hidden", background:DS.canvas }}>
                <div style={{ padding:"10px 16px", background:DS.canvasAlt, borderBottom:`1px solid ${DS.canvasBdr}` }}>
                  <div style={{ fontSize:12, fontWeight:700, color:DS.ink }}>◈ Issues Raised -- {draft.issues.length} identified</div>
                </div>
                <div style={{ maxHeight:260, overflowY:"auto" }}>
                  {draft.issues.map((issue, i) => (
                    <div key={i} style={{ padding:"9px 16px", display:"flex", alignItems:"flex-start", gap:10,
                      borderBottom:i<draft.issues.length-1?`1px solid ${DS.canvasBdr}`:"none" }}>
                      <div style={{ flex:1 }}>
                        <div style={{ fontSize:12, color:DS.ink, lineHeight:1.45, marginBottom:5 }}>{issue.text}</div>
                        <div style={{ display:"flex", gap:5, flexWrap:"wrap" }}>
                          <Badge variant={({Risk:"danger",Opportunity:"green",Regulatory:"amber",Financial:"blue",Technical:"chrome",Strategic:"blue"})[issue.type]||"default"} size="xs">{issue.type}</Badge>
                          <Badge variant={({Critical:"danger",High:"warn",Medium:"blue",Low:"default"})[issue.severity]||"default"} size="xs">{issue.severity}</Badge>
                          <Badge variant={confVar(issue.confidence)} size="xs">{issue.confidence}</Badge>
                        </div>
                      </div>
                      {issue.source && (
                        <div style={{ fontSize:10, color:DS.inkDis, fontStyle:"italic",
                          maxWidth:150, lineHeight:1.4, flexShrink:0 }}>
                          "{issue.source.slice(0,55)}…"
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* DECISIONS */}
            {accepted.decisions && draft.decisions?.length > 0 && (
              <div style={{ marginBottom:16, border:`1px solid ${DS.canvasBdr}`, borderRadius:8,
                overflow:"hidden", background:DS.canvas }}>
                <div style={{ padding:"10px 16px", background:DS.canvasAlt, borderBottom:`1px solid ${DS.canvasBdr}` }}>
                  <div style={{ fontSize:12, fontWeight:700, color:DS.ink }}>◧ Decision Hierarchy -- {draft.decisions.length} decisions</div>
                </div>
                <div style={{ padding:"12px 16px", display:"flex", flexDirection:"column", gap:10 }}>
                  {["given","focus","tactical","deferred","dependency"].map(tier => {
                    const td = draft.decisions.filter(d=>d.tier===tier);
                    if (!td.length) return null;
                    const tierDef = H_TIERS.find(t=>t.key===tier);
                    return (
                      <div key={tier}>
                        <div style={{ fontSize:10, fontWeight:700, letterSpacing:.6,
                          textTransform:"uppercase", marginBottom:6, color:tierDef?.color||DS.inkTer }}>
                          {tierDef?.icon} {tierDef?.label} ({td.length})
                        </div>
                        <div style={{ display:"flex", flexWrap:"wrap", gap:6 }}>
                          {td.map((d,i) => (
                            <div key={i} style={{ padding:"5px 10px", borderRadius:5, fontSize:11,
                              background:tierDef?.soft||DS.canvasAlt, color:tierDef?.color||DS.ink,
                              border:`1px solid ${tierDef?.line||DS.canvasBdr}`, fontWeight:600 }}>
                              {d.label}
                              <span style={{ fontWeight:400, color:DS.inkTer, marginLeft:4 }}>
                                ({d.choices?.length||0} options)
                              </span>
                            </div>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* CRITERIA */}
            {accepted.criteria && draft.criteria?.length > 0 && (
              <div style={{ marginBottom:16, border:`1px solid ${DS.canvasBdr}`, borderRadius:8,
                overflow:"hidden", background:DS.canvas }}>
                <div style={{ padding:"10px 16px", background:DS.canvasAlt, borderBottom:`1px solid ${DS.canvasBdr}` }}>
                  <div style={{ fontSize:12, fontWeight:700, color:DS.ink }}>◫ Decision Criteria -- {draft.criteria.length} criteria</div>
                </div>
                <div>
                  {draft.criteria.map((c,i) => (
                    <div key={i} style={{ padding:"9px 16px", display:"flex", alignItems:"center", gap:10,
                      borderBottom:i<draft.criteria.length-1?`1px solid ${DS.canvasBdr}`:"none" }}>
                      <div style={{ width:4, alignSelf:"stretch", borderRadius:2, flexShrink:0,
                        background:c.weight==="high"?DS.danger:c.weight==="medium"?DS.warning:DS.inkDis }}/>
                      <div style={{ flex:1 }}>
                        <div style={{ fontSize:12, fontWeight:700, color:DS.ink, marginBottom:2 }}>{c.label}</div>
                        <div style={{ fontSize:11, color:DS.inkSub }}>{c.description}</div>
                      </div>
                      <div style={{ display:"flex", gap:5 }}>
                        <Badge variant={({financial:"green",strategic:"blue",operational:"default",risk:"danger",commercial:"amber",technical:"chrome"})[c.type]||"default"} size="xs">{c.type}</Badge>
                        <Badge variant={({high:"danger",medium:"warn",low:"default"})[c.weight]||"default"} size="xs">{c.weight}</Badge>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* STRATEGIES */}
            {accepted.strategies && draft.strategies?.length > 0 && (
              <div style={{ marginBottom:16, border:`1px solid ${DS.canvasBdr}`, borderRadius:8,
                overflow:"hidden", background:DS.canvas }}>
                <div style={{ padding:"10px 16px", background:DS.canvasAlt, borderBottom:`1px solid ${DS.canvasBdr}` }}>
                  <div style={{ fontSize:12, fontWeight:700, color:DS.ink }}>⊞ Strategy Directions -- {draft.strategies.length} directions</div>
                </div>
                <div style={{ padding:"12px 16px", display:"grid",
                  gridTemplateColumns:"repeat(auto-fill,minmax(220px,1fr))", gap:10 }}>
                  {draft.strategies.map((s,i) => {
                    const col = DS.s[i%DS.s.length];
                    return (
                      <div key={i} style={{ padding:"13px 14px", borderRadius:7,
                        border:`1.5px solid ${col.line}`, background:col.soft }}>
                        <div style={{ fontSize:10, fontWeight:700, color:col.fill,
                          letterSpacing:.6, textTransform:"uppercase", marginBottom:5 }}>
                          {DS.sNames[i]||`Strategy ${i+1}`}
                        </div>
                        <div style={{ fontSize:13, fontWeight:700, color:DS.ink, marginBottom:5 }}>{s.name}</div>
                        <div style={{ fontSize:11, color:DS.inkSub, lineHeight:1.5, marginBottom:7 }}>{s.description}</div>
                        <div style={{ padding:"4px 8px", background:"rgba(255,255,255,.65)",
                          borderRadius:4, fontSize:10, color:DS.inkSub, fontStyle:"italic" }}>
                          {s.keyTheme}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}


            {/* BRUTAL TRUTHS */}
            {accepted.brutalTruths && (draft.brutalTruths?.length > 0) && (
              <div style={{ marginBottom:16, border:`1.5px solid #fecaca`, borderRadius:8,
                overflow:"hidden", background:"#fff5f5" }}>
                <div style={{ padding:"10px 16px", background:"#fee2e2",
                  borderBottom:"1px solid #fecaca", display:"flex", alignItems:"center", gap:8 }}>
                  <span style={{ fontSize:14 }}>⚑</span>
                  <div style={{ fontSize:12, fontWeight:700, color:"#dc2626" }}>
                    Brutal Truths -- {draft.brutalTruths.length} identified
                  </div>
                  <div style={{ marginLeft:"auto", fontSize:10, color:"#b91c1c" }}>
                    Things everyone knows but no one has written down
                  </div>
                </div>
                <div style={{ padding:"12px 16px", display:"flex", flexDirection:"column", gap:8 }}>
                  {draft.brutalTruths.map((bt, i) => (
                    <div key={i} style={{ padding:"10px 14px", background:"#fff",
                      border:"1px solid #fecaca", borderRadius:6 }}>
                      <div style={{ display:"flex", gap:8, alignItems:"flex-start" }}>
                        <span style={{ fontSize:9, fontWeight:700,
                          padding:"2px 6px", borderRadius:3,
                          background:bt.severity==="Critical"?"#dc2626":bt.severity==="High"?"#d97706":"#6b7280",
                          color:"#fff", flexShrink:0, marginTop:1 }}>
                          {bt.severity}
                        </span>
                        <div style={{ flex:1 }}>
                          <div style={{ fontSize:12, color:DS.ink, lineHeight:1.5, marginBottom:4,
                            fontWeight:600 }}>{bt.text}</div>
                          {bt.source && (
                            <div style={{ fontSize:10, color:"#b91c1c", fontStyle:"italic" }}>
                              From document: "{bt.source}"
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* INFORMATION GAPS */}
            {accepted.infoGaps && (draft.informationGaps?.length > 0) && (
              <div style={{ marginBottom:16, border:`1.5px solid #fde68a`, borderRadius:8,
                overflow:"hidden", background:"#fffdf0" }}>
                <div style={{ padding:"10px 16px", background:"#fef9c3",
                  borderBottom:"1px solid #fde68a", display:"flex", alignItems:"center", gap:8 }}>
                  <span style={{ fontSize:14 }}>◎</span>
                  <div style={{ fontSize:12, fontWeight:700, color:"#92400e" }}>
                    Information Gaps -- {draft.informationGaps.length} identified
                  </div>
                  <div style={{ marginLeft:"auto", fontSize:10, color:"#92400e" }}>
                    Unknown or unvalidated -- would affect the decision if resolved
                  </div>
                </div>
                <div style={{ padding:"12px 16px", display:"flex", flexDirection:"column", gap:8 }}>
                  {draft.informationGaps.map((ig, i) => (
                    <div key={i} style={{ padding:"10px 14px", background:"#fff",
                      border:"1px solid #fde68a", borderRadius:6 }}>
                      <div style={{ display:"flex", gap:8, alignItems:"flex-start" }}>
                        <span style={{ fontSize:9, fontWeight:700,
                          padding:"2px 6px", borderRadius:3,
                          background:ig.severity==="Critical"?"#dc2626":ig.severity==="High"?"#d97706":"#6b7280",
                          color:"#fff", flexShrink:0, marginTop:1 }}>
                          {ig.severity}
                        </span>
                        <div style={{ flex:1 }}>
                          <div style={{ fontSize:12, color:DS.ink, lineHeight:1.5,
                            fontWeight:600, marginBottom:4 }}>{ig.text}</div>
                          {ig.decisionImpact && (
                            <div style={{ fontSize:11, color:"#92400e", marginBottom:3 }}>
                              Decision impact: {ig.decisionImpact}
                            </div>
                          )}
                          {ig.source && (
                            <div style={{ fontSize:10, color:"#a16207", fontStyle:"italic" }}>
                              From document: "{ig.source}"
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* STAKEHOLDERS */}
            {accepted.stakeholders && (draft.stakeholders?.length > 0) && (
              <div style={{ marginBottom:16, border:`1px solid ${DS.canvasBdr}`, borderRadius:8,
                overflow:"hidden", background:DS.canvas }}>
                <div style={{ padding:"10px 16px", background:DS.canvasAlt,
                  borderBottom:`1px solid ${DS.canvasBdr}` }}>
                  <div style={{ fontSize:12, fontWeight:700, color:DS.ink }}>
                    ◉ Stakeholders -- {draft.stakeholders.length} identified
                  </div>
                </div>
                <div style={{ padding:"12px 16px", display:"grid",
                  gridTemplateColumns:"repeat(auto-fill,minmax(240px,1fr))", gap:10 }}>
                  {draft.stakeholders.map((sh, i) => {
                    const alCol = {champion:"#059669",neutral:"#6b7280",skeptic:"#d97706",blocker:"#dc2626"}[sh.alignment]||"#6b7280";
                    return (
                      <div key={i} style={{ padding:"10px 13px",
                        border:`1px solid ${alCol}30`, borderRadius:7,
                        background:`${alCol}08` }}>
                        <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:5 }}>
                          <div style={{ fontSize:11, fontWeight:700, color:DS.ink }}>
                            {sh.name}
                          </div>
                          <span style={{ fontSize:9, fontWeight:700, padding:"1px 5px",
                            borderRadius:3, background:alCol+"20", color:alCol }}>
                            {sh.alignment}
                          </span>
                          {sh.isInferred && (
                            <span style={{ fontSize:8, color:DS.inkDis, fontStyle:"italic" }}>inferred</span>
                          )}
                        </div>
                        <div style={{ fontSize:10, color:DS.inkSub, marginBottom:4 }}>{sh.role}</div>
                        {sh.primaryConcern && (
                          <div style={{ fontSize:10, color:DS.inkTer, fontStyle:"italic",
                            lineHeight:1.4 }}>{sh.primaryConcern}</div>
                        )}
                        <div style={{ display:"flex", gap:4, marginTop:5 }}>
                          <span style={{ fontSize:8, fontWeight:700, padding:"1px 5px",
                            borderRadius:3, background:DS.canvasBdr, color:DS.inkTer }}>
                            {sh.influence} influence
                          </span>
                          {sh.mustAlign && (
                            <span style={{ fontSize:8, fontWeight:700, padding:"1px 5px",
                              borderRadius:3, background:"#fef2f2", color:"#dc2626" }}>
                              must align
                            </span>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* UNCERTAINTIES */}
            {accepted.uncertainties && (draft.uncertainties?.length > 0) && (
              <div style={{ marginBottom:16, border:`1px solid ${DS.canvasBdr}`, borderRadius:8,
                overflow:"hidden", background:DS.canvas }}>
                <div style={{ padding:"10px 16px", background:DS.canvasAlt,
                  borderBottom:`1px solid ${DS.canvasBdr}`, display:"flex", alignItems:"center", gap:8 }}>
                  <div style={{ fontSize:12, fontWeight:700, color:DS.ink }}>
                    ◈ Key Uncertainties -- {draft.uncertainties.length} identified
                  </div>
                  <div style={{ marginLeft:"auto", fontSize:10, color:DS.inkTer }}>
                    Seeds Scenario Planning + Value of Information modules
                  </div>
                </div>
                <div style={{ padding:"12px 16px", display:"flex", flexDirection:"column", gap:8 }}>
                  {draft.uncertainties.map((unc, i) => (
                    <div key={i} style={{ padding:"10px 14px",
                      border:`1px solid ${DS.canvasBdr}`, borderRadius:6 }}>
                      <div style={{ fontSize:12, fontWeight:700, color:DS.ink,
                        marginBottom:4 }}>{unc.label}</div>
                      <div style={{ fontSize:11, color:DS.inkSub, lineHeight:1.5,
                        marginBottom:5 }}>{unc.description}</div>
                      <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
                        {unc.decisionImpact && (
                          <span style={{ fontSize:9, color:DS.inkTer,
                            padding:"1px 6px", background:DS.canvasAlt,
                            borderRadius:3 }}>
                            Impact: {unc.decisionImpact}
                          </span>
                        )}
                        {unc.resolvable && (
                          <span style={{ fontSize:9, fontWeight:700,
                            padding:"1px 6px", borderRadius:3,
                            background:unc.resolvable==="yes"?"#ecfdf5":unc.resolvable==="partially"?"#fffbeb":"#fef2f2",
                            color:unc.resolvable==="yes"?"#059669":unc.resolvable==="partially"?"#d97706":"#dc2626" }}>
                            {unc.resolvable==="yes"?"Resolvable":unc.resolvable==="partially"?"Partially resolvable":"Irreducible"}
                          </span>
                        )}
                      </div>
                      {unc.resolutionPath && (
                        <div style={{ fontSize:10, color:DS.accent, marginTop:4 }}>
                          → {unc.resolutionPath}
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* GAME THEORY */}
            {accepted.gameTheory && draft.gameTheorySignals?.hasStrategicInteraction && (
              <div style={{ marginBottom:16, border:"1.5px solid rgba(99,102,241,.3)",
                borderRadius:8, overflow:"hidden",
                background:"rgba(99,102,241,.03)" }}>
                <div style={{ padding:"10px 16px",
                  background:"rgba(99,102,241,.08)",
                  borderBottom:"1px solid rgba(99,102,241,.2)",
                  display:"flex", alignItems:"center", gap:8 }}>
                  <span style={{ fontSize:16 }}>♟</span>
                  <div style={{ flex:1 }}>
                    <div style={{ fontSize:12, fontWeight:700, color:"#4f46e5" }}>
                      Game Theory Signals Detected
                    </div>
                    <div style={{ fontSize:10, color:"#6366f1" }}>
                      This decision involves strategic interaction -- Game Theory module recommended
                    </div>
                  </div>
                  <span style={{ fontSize:11, fontWeight:700, padding:"3px 10px",
                    background:"rgba(99,102,241,.15)", color:"#6366f1",
                    borderRadius:5 }}>
                    {draft.gameTheorySignals.gameType}
                  </span>
                </div>
                <div style={{ padding:"14px 16px" }}>
                  <div style={{ fontSize:12, color:DS.ink, lineHeight:1.5, marginBottom:12 }}>
                    {draft.gameTheorySignals.rationale}
                  </div>
                  {draft.gameTheorySignals.mostImportantDynamic && (
                    <div style={{ padding:"8px 12px",
                      background:"rgba(99,102,241,.06)",
                      border:"1px solid rgba(99,102,241,.15)",
                      borderRadius:6, fontSize:11, color:"#6366f1",
                      fontStyle:"italic", marginBottom:12 }}>
                      Key dynamic: {draft.gameTheorySignals.mostImportantDynamic}
                    </div>
                  )}
                  {(draft.gameTheorySignals.keyPlayers||[]).length > 0 && (
                    <div>
                      <div style={{ fontSize:10, fontWeight:700, color:DS.inkTer,
                        textTransform:"uppercase", letterSpacing:.5, marginBottom:8 }}>
                        Key Players
                      </div>
                      <div style={{ display:"grid",
                        gridTemplateColumns:"repeat(auto-fill,minmax(200px,1fr))", gap:8 }}>
                        {draft.gameTheorySignals.keyPlayers.map((pl,i) => (
                          <div key={i} style={{ padding:"8px 12px",
                            background:"rgba(99,102,241,.06)",
                            border:"1px solid rgba(99,102,241,.1)",
                            borderRadius:6 }}>
                            <div style={{ fontSize:11, fontWeight:700,
                              color:"#4f46e5", marginBottom:3 }}>{pl.name}</div>
                            <div style={{ fontSize:10, color:DS.inkSub,
                              marginBottom:3 }}>{pl.objective}</div>
                            <div style={{ fontSize:9, color:"#6366f1" }}>
                              Key move: {pl.keyMove}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            )}


            {/* INFLUENCE MAP */}
            {accepted.influence && (draft.influenceNodes?.length > 0) && (
              <div style={{ marginBottom:16, border:`1px solid ${DS.canvasBdr}`, borderRadius:8, overflow:"hidden", background:DS.canvas }}>
                <div style={{ padding:"10px 16px", background:DS.canvasAlt, borderBottom:`1px solid ${DS.canvasBdr}`, display:"flex", alignItems:"center", gap:8 }}>
                  <div style={{ fontSize:12, fontWeight:700, color:DS.ink }}>⊕ Influence Map -- {draft.influenceNodes.length} nodes · {draft.influenceEdges?.length||0} edges</div>
                  <div style={{ marginLeft:"auto", fontSize:10, color:DS.inkTer }}>Seeds Influence Map module</div>
                </div>
                <div style={{ padding:"12px 16px" }}>
                  <div style={{ display:"flex", gap:6, flexWrap:"wrap", marginBottom:10 }}>
                    {["decision","uncertainty","value","constraint","external","objective"].map(type => {
                      const count = draft.influenceNodes.filter(n=>n.type===type).length;
                      if (!count) return null;
                      const colors = {decision:"#2563eb",uncertainty:"#d97706",value:"#059669",constraint:"#dc2626",external:"#6b7280",objective:"#7c3aed"};
                      return <span key={type} style={{ fontSize:10, fontWeight:700, padding:"2px 8px", borderRadius:4, background:colors[type]+"18", color:colors[type] }}>{type} ×{count}</span>;
                    })}
                  </div>
                  <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fill,minmax(200px,1fr))", gap:8 }}>
                    {draft.influenceNodes.slice(0,12).map((n,i) => {
                      const colors = {decision:"#2563eb",uncertainty:"#d97706",value:"#059669",constraint:"#dc2626",external:"#6b7280",objective:"#7c3aed"};
                      const col = colors[n.type]||"#6b7280";
                      return (
                        <div key={i} style={{ padding:"8px 10px", border:`1px solid ${col}25`, borderRadius:6, background:`${col}08` }}>
                          <div style={{ fontSize:9, fontWeight:700, color:col, textTransform:"uppercase", letterSpacing:.5, marginBottom:3 }}>{n.type}</div>
                          <div style={{ fontSize:11, fontWeight:700, color:DS.ink, marginBottom:2 }}>{n.label}</div>
                          <div style={{ fontSize:10, color:DS.inkTer, lineHeight:1.4 }}>{n.description}</div>
                          {n.confidence && <div style={{ fontSize:8, color:DS.inkDis, marginTop:3 }}>{n.confidence} confidence{n.source?" · "+n.source:""}</div>}
                        </div>
                      );
                    })}
                  </div>
                  {draft.influenceEdges?.length > 0 && (
                    <div style={{ marginTop:10, padding:"8px 10px", background:DS.canvasAlt, borderRadius:6, fontSize:10, color:DS.inkTer }}>
                      <span style={{ fontWeight:700, color:DS.inkSub }}>Key relationships: </span>
                      {draft.influenceEdges.slice(0,6).map((e,i) => (
                        <span key={i}>{e.source} → {e.target} ({e.strength}){i<5?", ":""}</span>
                      ))}
                      {draft.influenceEdges.length > 6 && <span> +{draft.influenceEdges.length-6} more</span>}
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* SCENARIOS */}
            {accepted.scenarios && (draft.scenarioNarratives?.length > 0) && (
              <div style={{ marginBottom:16, border:`1px solid ${DS.canvasBdr}`, borderRadius:8, overflow:"hidden", background:DS.canvas }}>
                <div style={{ padding:"10px 16px", background:DS.canvasAlt, borderBottom:`1px solid ${DS.canvasBdr}`, display:"flex", alignItems:"center", gap:8 }}>
                  <div style={{ fontSize:12, fontWeight:700, color:DS.ink }}>◈ Scenario Framework -- {draft.scenarioNarratives.length} scenarios</div>
                  {draft.scenarioAxes && (
                    <div style={{ fontSize:10, color:DS.inkTer }}>
                      Axes: {draft.scenarioAxes.axis1?.label} × {draft.scenarioAxes.axis2?.label}
                    </div>
                  )}
                </div>
                <div style={{ padding:"12px 16px" }}>
                  <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:10 }}>
                    {draft.scenarioNarratives.map((sc,i) => (
                      <div key={i} style={{ padding:"10px 14px", border:`1px solid ${DS.canvasBdr}`, borderRadius:7,
                        background:i===0?"rgba(5,150,105,.04)":i===1?"rgba(245,158,11,.04)":i===2?"rgba(220,38,38,.04)":"rgba(107,114,128,.04)" }}>
                        <div style={{ fontSize:11, fontWeight:700, color:DS.ink, marginBottom:4 }}>{sc.name}</div>
                        <div style={{ fontSize:10, color:DS.inkSub, lineHeight:1.5, marginBottom:6 }}>{sc.narrative}</div>
                        {sc.bestStrategy && (
                          <div style={{ fontSize:9, color:"#059669", fontStyle:"italic" }}>Best strategy: {sc.bestStrategy}</div>
                        )}
                        {sc.earlyWarnings?.length > 0 && (
                          <div style={{ marginTop:5, fontSize:9, color:DS.inkTer }}>⚠ {sc.earlyWarnings[0]}</div>
                        )}
                      </div>
                    ))}
                  </div>
                  {draft.mostDangerousScenario && (
                    <div style={{ padding:"6px 10px", background:"rgba(220,38,38,.06)", border:"1px solid rgba(220,38,38,.2)", borderRadius:5, fontSize:10, color:"#dc2626" }}>
                      ⚠ Most dangerous: {draft.mostDangerousScenario}
                    </div>
                  )}
                  {draft.robustStrategy && (
                    <div style={{ marginTop:6, padding:"6px 10px", background:"rgba(5,150,105,.06)", border:"1px solid rgba(5,150,105,.2)", borderRadius:5, fontSize:10, color:"#059669" }}>
                      ✓ Most robust strategy: {draft.robustStrategy}
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* VALUE OF INFORMATION */}
            {accepted.voi && (draft.voiItems?.length > 0) && (
              <div style={{ marginBottom:16, border:`1px solid ${DS.canvasBdr}`, borderRadius:8, overflow:"hidden", background:DS.canvas }}>
                <div style={{ padding:"10px 16px", background:DS.canvasAlt, borderBottom:`1px solid ${DS.canvasBdr}`, display:"flex", alignItems:"center", gap:8 }}>
                  <div style={{ fontSize:12, fontWeight:700, color:DS.ink }}>◎ Value of Information -- {draft.voiItems.length} items</div>
                  <div style={{ marginLeft:"auto", fontSize:10, color:DS.inkTer }}>Seeds VoI module</div>
                </div>
                <div style={{ padding:"12px 16px", display:"flex", flexDirection:"column", gap:8 }}>
                  {draft.voiItems.map((v,i) => {
                    const cls = v.classification;
                    const clsCol = {do_now:"#dc2626",do_later:"#d97706",conditional:"#6b7280",do_not_do:"#94a3b8"}[cls]||"#6b7280";
                    const clsLabel = {do_now:"Do Now",do_later:"Do Later",conditional:"If Trigger",do_not_do:"Do Not Do"}[cls]||cls;
                    return (
                      <div key={i} style={{ padding:"10px 14px", border:`1px solid ${clsCol}25`, borderRadius:6, background:`${clsCol}06` }}>
                        <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:5 }}>
                          <span style={{ fontSize:9, fontWeight:700, padding:"2px 7px", borderRadius:3, background:clsCol+"20", color:clsCol }}>{clsLabel}</span>
                          <div style={{ fontSize:11, fontWeight:700, color:DS.ink }}>{v.label}</div>
                        </div>
                        <div style={{ fontSize:10, color:DS.inkSub, lineHeight:1.4, marginBottom:4 }}>{v.description}</div>
                        {v.action && <div style={{ fontSize:10, color:DS.accent }}>→ Action: {v.action}</div>}
                        {v.decisionPivot && <div style={{ fontSize:10, color:DS.inkTer, fontStyle:"italic", marginTop:3 }}>{v.decisionPivot}</div>}
                        <div style={{ display:"flex", gap:6, marginTop:4 }}>
                          {v.timeToLearn && <span style={{ fontSize:8, color:DS.inkDis }}>Time: {v.timeToLearn}</span>}
                          {v.costEstimate && <span style={{ fontSize:8, color:DS.inkDis }}>Cost: {v.costEstimate}</span>}
                        </div>
                      </div>
                    );
                  })}
                  {draft.voiSummary && (
                    <div style={{ padding:"8px 12px", background:DS.canvasAlt, borderRadius:6, fontSize:11, color:DS.inkSub, fontStyle:"italic" }}>
                      {draft.voiSummary}
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* RISK TIMELINE */}
            {accepted.timeline && (draft.timelineEvents?.length > 0) && (
              <div style={{ marginBottom:16, border:`1px solid ${DS.canvasBdr}`, borderRadius:8, overflow:"hidden", background:DS.canvas }}>
                <div style={{ padding:"10px 16px", background:DS.canvasAlt, borderBottom:`1px solid ${DS.canvasBdr}`, display:"flex", alignItems:"center", gap:8 }}>
                  <div style={{ fontSize:12, fontWeight:700, color:DS.ink }}>⊳ Risk Timeline -- {draft.timelineEvents.length} events</div>
                  <div style={{ marginLeft:"auto", fontSize:10, color:DS.inkTer }}>Seeds Timeline module</div>
                </div>
                <div style={{ padding:"12px 16px" }}>
                  <div style={{ display:"flex", flexDirection:"column", gap:6 }}>
                    {draft.timelineEvents.sort((a,b)=>(a.timing||0)-(b.timing||0)).map((ev,i) => {
                      const typeColors = {decision_gate:"#7c3aed",risk_event:"#dc2626",milestone:"#059669",implementation:"#2563eb",review:"#6b7280"};
                      const col = typeColors[ev.type]||"#6b7280";
                      const sevCol = {Critical:"#dc2626",High:"#d97706",Medium:"#6b7280",Low:"#94a3b8"}[ev.severity]||"#6b7280";
                      return (
                        <div key={i} style={{ display:"flex", gap:10, alignItems:"flex-start" }}>
                          <div style={{ flexShrink:0, width:48, textAlign:"center" }}>
                            <div style={{ fontSize:9, fontWeight:700, color:col }}>M{ev.timing||"?"}</div>
                            <div style={{ width:1, height:20, background:DS.canvasBdr, margin:"2px auto" }}/>
                          </div>
                          <div style={{ flex:1, padding:"8px 10px", border:`1px solid ${col}25`, borderRadius:6, background:`${col}06` }}>
                            <div style={{ display:"flex", alignItems:"center", gap:6, marginBottom:3 }}>
                              <span style={{ fontSize:9, fontWeight:700, padding:"1px 5px", borderRadius:3, background:col+"20", color:col }}>
                                {ev.type?.replace("_"," ")||"event"}
                              </span>
                              <span style={{ fontSize:9, fontWeight:700, color:sevCol }}>{ev.severity}</span>
                              <div style={{ fontSize:11, fontWeight:700, color:DS.ink }}>{ev.title}</div>
                            </div>
                            <div style={{ fontSize:10, color:DS.inkSub, lineHeight:1.4, marginBottom:ev.gateCondition?4:0 }}>{ev.description}</div>
                            {ev.gateCondition && (
                              <div style={{ fontSize:9, color:"#7c3aed", fontStyle:"italic" }}>Gate: {ev.gateCondition}</div>
                            )}
                            {ev.mitigation && (
                              <div style={{ fontSize:9, color:"#059669", marginTop:3 }}>→ {ev.mitigation}</div>
                            )}
                          </div>
                        </div>
                      );
                    })}
                  </div>
                  {draft.criticalPath && (
                    <div style={{ marginTop:10, padding:"6px 10px", background:DS.canvasAlt, borderRadius:5, fontSize:10, color:DS.inkTer }}>
                      <span style={{ fontWeight:700, color:DS.inkSub }}>Critical path: </span>{draft.criticalPath}
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* DQ SCORECARD + VALIDATION FLAGS */}
            {accepted.scorecard && draft.dqScores && (
              <div style={{ marginBottom:16, border:`1px solid ${DS.canvasBdr}`, borderRadius:8, overflow:"hidden", background:DS.canvas }}>
                <div style={{ padding:"10px 16px", background:DS.canvasAlt, borderBottom:`1px solid ${DS.canvasBdr}`, display:"flex", alignItems:"center", gap:8 }}>
                  <div style={{ fontSize:12, fontWeight:700, color:DS.ink }}>◉ DQ Scorecard -- Preliminary Assessment</div>
                  {draft.readinessVerdict && (
                    <span style={{ fontSize:10, fontWeight:700, padding:"2px 8px", borderRadius:4,
                      background:draft.readinessVerdict==="ready"?"rgba(5,150,105,.15)":draft.readinessVerdict==="conditional"?"rgba(245,158,11,.15)":"rgba(220,38,38,.15)",
                      color:draft.readinessVerdict==="ready"?"#059669":draft.readinessVerdict==="conditional"?"#d97706":"#dc2626" }}>
                      {draft.readinessVerdict==="ready"?"Decision Ready":draft.readinessVerdict==="conditional"?"Conditionally Ready":"Not Ready"}
                    </span>
                  )}
                </div>
                <div style={{ padding:"14px 16px" }}>
                  <div style={{ display:"grid", gridTemplateColumns:"repeat(3,1fr)", gap:10, marginBottom:12 }}>
                    {[["frame","Frame"],["alternatives","Alternatives"],["information","Information"],["values","Values"],["reasoning","Reasoning"],["commitment","Commitment"]].map(([key,label]) => {
                      const score = draft.dqScores[key]||0;
                      const col = score>=70?"#059669":score>=45?"#d97706":"#dc2626";
                      return (
                        <div key={key} style={{ padding:"8px 10px", border:`1px solid ${col}25`, borderRadius:6, textAlign:"center" }}>
                          <div style={{ fontSize:9, color:DS.inkTer, textTransform:"uppercase", letterSpacing:.5, marginBottom:3 }}>{label}</div>
                          <div style={{ fontSize:24, fontWeight:700, color:col, fontFamily:"'Libre Baskerville',serif" }}>{score}</div>
                          <div style={{ height:3, background:DS.canvasBdr, borderRadius:2, overflow:"hidden", marginTop:4 }}>
                            <div style={{ height:"100%", width:score+"%", background:col, borderRadius:2 }}/>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                  {draft.dqNarrative && (
                    <div style={{ padding:"8px 12px", background:DS.canvasAlt, borderRadius:6, fontSize:11, color:DS.inkSub, fontStyle:"italic", marginBottom:10 }}>
                      {draft.dqNarrative}
                    </div>
                  )}
                  {draft.validationFlags?.length > 0 && (
                    <div>
                      <div style={{ fontSize:10, fontWeight:700, color:DS.ink, marginBottom:8 }}>
                        Validation Flags ({draft.validationFlags.length})
                      </div>
                      <div style={{ display:"flex", flexDirection:"column", gap:5 }}>
                        {draft.validationFlags.map((f,i) => {
                          const sevCol = {critical:"#dc2626",warning:"#d97706",info:"#6b7280"}[f.severity]||"#6b7280";
                          return (
                            <div key={i} style={{ display:"flex", gap:8, padding:"7px 10px", border:`1px solid ${sevCol}25`, borderRadius:5, background:`${sevCol}06` }}>
                              <span style={{ fontSize:9, fontWeight:700, color:sevCol, flexShrink:0, padding:"1px 5px", background:sevCol+"20", borderRadius:3, height:"fit-content" }}>
                                {f.severity}
                              </span>
                              <div style={{ flex:1 }}>
                                <div style={{ fontSize:11, color:DS.ink, marginBottom:2 }}>{f.message}</div>
                                {f.suggestion && <div style={{ fontSize:10, color:DS.accent }}>→ {f.suggestion}</div>}
                              </div>
                            </div>
                          );
                        })}
                      </div>
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* CROSS-MODULE INTELLIGENCE */}
            {accepted.crossModule && draft.crossModuleInsights && (
              <div style={{ marginBottom:16, border:"1.5px solid rgba(99,102,241,.25)", borderRadius:8, overflow:"hidden", background:"rgba(99,102,241,.02)" }}>
                <div style={{ padding:"10px 16px", background:"rgba(99,102,241,.06)", borderBottom:"1px solid rgba(99,102,241,.15)", display:"flex", alignItems:"center", gap:8 }}>
                  <span style={{ fontSize:14 }}>✦</span>
                  <div style={{ fontSize:12, fontWeight:700, color:"#4f46e5" }}>Cross-Module Intelligence</div>
                  <div style={{ fontSize:10, color:"#6366f1", marginLeft:"auto" }}>Contradictions, orphan risks, strategic tensions</div>
                </div>
                <div style={{ padding:"14px 16px", display:"grid", gridTemplateColumns:"1fr 1fr", gap:14 }}>
                  {[
                    { key:"contradictions",          label:"Contradictions",               col:"#dc2626" },
                    { key:"framingDriftRisks",        label:"Framing Drift Risks",          col:"#d97706" },
                    { key:"orphanRisks",              label:"Orphan Risks",                 col:"#7c3aed" },
                    { key:"missingDownstreamAnalysis",label:"Missing Downstream Analysis",  col:"#6b7280" },
                    { key:"strategicTensions",        label:"Strategic Tensions",           col:"#0891b2" },
                  ].map(({ key, label, col }) => {
                    const items = draft.crossModuleInsights[key];
                    if (!items?.length) return null;
                    return (
                      <div key={key} style={{ padding:"10px 12px", border:`1px solid ${col}20`, borderRadius:7, background:`${col}05` }}>
                        <div style={{ fontSize:9, fontWeight:700, color:col, textTransform:"uppercase", letterSpacing:.5, marginBottom:7 }}>{label}</div>
                        <div style={{ display:"flex", flexDirection:"column", gap:4 }}>
                          {items.map((item,i) => (
                            <div key={i} style={{ fontSize:10, color:DS.inkSub, lineHeight:1.4, paddingLeft:8, borderLeft:`2px solid ${col}40` }}>
                              {item}
                            </div>
                          ))}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}

            {/* Load CTA */}
            <div style={{ padding:"18px 22px", background:DS.accentSoft, border:`1px solid ${DS.accentLine}`,
              borderRadius:10, display:"flex", alignItems:"center", justifyContent:"space-between", gap:16 }}>
              <div>
                <div style={{ fontSize:13, fontWeight:700, color:DS.ink, marginBottom:4 }}>
                  Ready to load your first draft?
                </div>
                <div style={{ fontSize:12, color:DS.inkSub }}>
                  {Object.values(accepted).filter(Boolean).length}/{sections.length} sections selected · Everything is editable once loaded.
                </div>
              </div>
              <Btn variant="primary" icon="check" size="lg" onClick={applyDraft}>Load First Draft →</Btn>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return null;
}

/* ─────────────────────────────────────────────────────────────────────────────
/* ─────────────────────────────────────────────────────────────────────────────
   ROOT APPLICATION -- FINISHED BUILD
   Nav overhaul · Polish · PDF Export · Onboarding · Responsive
───────────────────────────────────────────────────────────────────────────── */

/* ── MODULE REGISTRY ──────────────────────────────────────────────────────── */
const PHASE1 = [
  { id:"problem",      num:"01", label:"Problem Definition",     sub:"Frame the decision",        icon:"\u25ce" },
  { id:"issues",       num:"02", label:"Issue Raising",          sub:"Surface what matters",      icon:"\u25c8" },
  { id:"hierarchy",    num:"03", label:"Decision Hierarchy",     sub:"Structure & prioritise",    icon:"\u25a7" },
  { id:"strategy",     num:"04", label:"Strategy Table",         sub:"Build alternatives",        icon:"\u229e" },
  { id:"assessment",   num:"05", label:"Qualitative Assessment", sub:"Score & compare",           icon:"\u25ab" },
  { id:"scorecard",    num:"06", label:"DQ Scorecard",           sub:"Chain analysis",            icon:"\u25d1" },
  { id:"stakeholders", num:"07", label:"Stakeholder Alignment",  sub:"Map & align key players",   icon:"\u25c9" },
  { id:"export",       num:"08", label:"Export & Report",        sub:"Executive package",         icon:"\u25d0" },
];
const PHASE2 = [
  { id:"influence",  num:"09", label:"Influence Map",          sub:"Causal structure",           icon:"\u2295" },
  { id:"scenarios",  num:"10", label:"Scenario Planning",      sub:"Test across futures",        icon:"\u25c8" },
  { id:"voi",        num:"11", label:"Value of Information",   sub:"What to resolve first",      icon:"\u25ce" },
  { id:"timeline",   num:"12", label:"Decision Risk Timeline", sub:"Time, gates & risk",         icon:"\u22b3" },
];
const MODULES = [...PHASE1, ...PHASE2];

const MODULE_NUDGES = {
  problem:    "Check if this is truly a decision -- or a goal in disguise",
  issues:     "Generate issues from 5 stakeholder perspectives for this decision",
  hierarchy:  "Auto-sort the decision hierarchy across all 5 tiers",
  strategy:   "Suggest 2 genuinely distinct strategies and check coherence",
  assessment: "Score strategies and generate a decision brief",
  scorecard:  "Generate the full DQ report -- identify the weakest link",
  export:     "Generate the executive package ready for the board",
  influence:  "Identify key drivers and deal-breaker scenarios",
};

/* ── PDF EXPORT ENGINE ────────────────────────────────────────────────────── */
function buildPDFContent(problem, issues, decisions, strategies, criteria,
  assessmentScores, dqScores, brief, narrative) {

  const focusDecs  = decisions.filter(d=>d.tier==="focus");
  const scoreColor = s => s>=70?"#059669":s>=45?"#d97706":"#dc2626";
  const pct = (s) => {
    if (!criteria.length) return 0;
    const total = criteria.reduce((sum,c)=>{
      const w = 2;
      return sum + (assessmentScores[`${s.id}__${c.id}`]||0)*w;
    },0);
    const max = criteria.length*5*2;
    return max>0 ? Math.round((total/max)*100) : 0;
  };
  const overall = DQ_ELEMENTS.length>0
    ? Math.round(DQ_ELEMENTS.reduce((s,e)=>s+(dqScores[e.key]||0),0)/DQ_ELEMENTS.length)
    : 0;

  return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8"/>
<title>${problem.projectName||"Decision Package"} -- Vantage DQ</title>
<style>
  @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;500;600;700&family=Libre+Baskerville:ital,wght@0,700;1,400&display=swap');
  *{box-sizing:border-box;margin:0;padding:0}
  body{font-family:'IBM Plex Sans','Helvetica Neue',sans-serif;color:#0d0f18;background:#fff;font-size:11px;line-height:1.5}
  .page{width:210mm;min-height:297mm;padding:16mm 18mm;background:#fff;margin:0 auto}
  @media print{.page{padding:12mm 14mm;margin:0}.no-print{display:none!important}@page{size:A4;margin:0}}
  h1{font-family:'Libre Baskerville',Georgia,serif;font-size:22px;font-weight:700;line-height:1.2;letter-spacing:-.3px}
  h2{font-family:'Libre Baskerville',Georgia,serif;font-size:14px;font-weight:700;margin-bottom:8px;color:#0d0f18}
  h3{font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.8px;color:#7b82a0;margin-bottom:6px}
  .header{display:flex;align-items:flex-start;gap:16px;padding-bottom:14px;border-bottom:2px solid #0d0f18;margin-bottom:20px}
  .logo-box{width:36px;height:36px;background:#2563eb;border-radius:6px;display:flex;align-items:center;justify-content:center;flex-shrink:0}
  .badge{display:inline-flex;align-items:center;padding:2px 8px;border-radius:3px;font-size:9px;font-weight:700;letter-spacing:.5px;text-transform:uppercase;border:1px solid}
  .badge-blue{background:#eff4ff;color:#2563eb;border-color:#bfdbfe}
  .badge-green{background:#ecfdf5;color:#059669;border-color:#a7f3d0}
  .badge-warn{background:#fffbeb;color:#d97706;border-color:#fde68a}
  .badge-danger{background:#fef2f2;color:#dc2626;border-color:#fecaca}
  .badge-grey{background:#f3f4f6;color:#374151;border-color:#d1d5db}
  .section{margin-bottom:18px}
  .box{padding:12px 14px;border-radius:6px;border:1px solid;margin-bottom:10px}
  .box-blue{background:#eff4ff;border-color:#bfdbfe}
  .box-green{background:#ecfdf5;border-color:#a7f3d0}
  .box-warn{background:#fffbeb;border-color:#fde68a}
  .box-danger{background:#fef2f2;border-color:#fecaca}
  .box-grey{background:#f9fafb;border-color:#e5e7eb}
  table{width:100%;border-collapse:collapse;font-size:10px}
  th{padding:6px 10px;text-align:left;font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.6px;color:#7b82a0;border-bottom:1px solid #e2e5ee;background:#f4f5f8}
  td{padding:7px 10px;border-bottom:1px solid #e2e5ee;vertical-align:top}
  tr:last-child td{border-bottom:none}
  .score-big{font-family:'Libre Baskerville',Georgia,serif;font-size:28px;font-weight:700;line-height:1}
  .bar-track{height:5px;background:#e2e5ee;border-radius:3px;overflow:hidden;margin-top:4px}
  .bar-fill{height:100%;border-radius:3px}
  .grid2{display:grid;grid-template-columns:1fr 1fr;gap:12px}
  .grid3{display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px}
  .page-break{page-break-before:always;padding-top:16mm}
  .meta-row{display:flex;gap:20px;flex-wrap:wrap;margin-top:6px}
  .meta-item{display:flex;flex-direction:column;gap:2px}
  .meta-label{font-size:8px;text-transform:uppercase;letter-spacing:.8px;color:#9ca3af;font-weight:700}
  .meta-value{font-size:10px;font-weight:600;color:#3d4260}
  .strat-dot{display:inline-block;width:8px;height:8px;border-radius:50%;margin-right:4px;vertical-align:middle}
  .footer{margin-top:20px;padding-top:10px;border-top:1px solid #e2e5ee;display:flex;justify-content:space-between;color:#9ca3af;font-size:8px}
  .print-btn{position:fixed;bottom:24px;right:24px;padding:10px 20px;background:#2563eb;color:#fff;border:none;border-radius:8px;font-family:inherit;font-size:13px;font-weight:700;cursor:pointer;box-shadow:0 4px 16px rgba(37,99,235,.35)}
</style>
</head>
<body>
<button class="print-btn no-print" onclick="window.print()">🖨 Print / Save PDF</button>

<div class="page">

  <!-- HEADER -->
  <div class="header">
    <div class="logo-box">
      <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.5" stroke-linecap="round">
        <polygon points="12,2 22,8.5 22,15.5 12,22 2,15.5 2,8.5"/>
        <line x1="12" y1="2" x2="12" y2="22"/>
        <line x1="2" y1="8.5" x2="22" y2="8.5"/>
        <line x1="2" y1="15.5" x2="22" y2="15.5"/>
      </svg>
    </div>
    <div style="flex:1">
      <div style="font-size:8px;text-transform:uppercase;letter-spacing:1.5px;color:#9ca3af;margin-bottom:4px">Vantage DQ · Decision Quality Platform</div>
      <h1>${problem.projectName||"Decision Package"}</h1>
      <div style="margin-top:6px;display:flex;gap:6px;flex-wrap:wrap">
        ${problem.projectCode?`<span class="badge badge-grey">${problem.projectCode}</span>`:""}
        ${problem.sector?`<span class="badge badge-blue">${problem.sector.split("/")[0].trim()}</span>`:""}
        ${problem.decisionType?`<span class="badge badge-grey">${problem.decisionType}</span>`:""}
        ${problem.confidentiality&&problem.confidentiality!=="Internal"?`<span class="badge badge-warn">${problem.confidentiality}</span>`:""}
      </div>
    </div>
    <div style="text-align:right;flex-shrink:0">
      ${problem.sessionDate?`<div class="meta-item" style="align-items:flex-end"><div class="meta-label">Date</div><div class="meta-value">${new Date(problem.sessionDate).toLocaleDateString("en-GB",{day:"numeric",month:"long",year:"numeric"})}</div></div>`:""}
      ${problem.facilitator?`<div class="meta-item" style="align-items:flex-end;margin-top:6px"><div class="meta-label">Facilitator</div><div class="meta-value">${problem.facilitator}</div></div>`:""}
      ${problem.owner?`<div class="meta-item" style="align-items:flex-end;margin-top:6px"><div class="meta-label">Decision Owner</div><div class="meta-value">${problem.owner}</div></div>`:""}
    </div>
  </div>

  <!-- 1. DECISION FRAME -->
  <div class="section">
    <h2>1. Decision Frame</h2>
    <div class="box box-blue" style="margin-bottom:8px">
      <div style="font-size:8px;text-transform:uppercase;letter-spacing:.8px;color:#2563eb;font-weight:700;margin-bottom:4px">Decision Statement</div>
      <div style="font-family:'Libre Baskerville',Georgia,serif;font-size:12px;font-style:italic;line-height:1.5">"${problem.decisionStatement}"</div>
    </div>
    <div class="grid2">
      ${[
        ["Context",problem.context],
        ["Trigger",problem.trigger],
        ["Scope In",problem.scopeIn],
        ["Scope Out",problem.scopeOut],
        ["Constraints",problem.constraints],
        ["Success Criteria",problem.successCriteria],
      ].filter(([,v])=>v).map(([l,v])=>`
        <div>
          <div class="meta-label">${l}</div>
          <div style="font-size:10px;margin-top:3px;line-height:1.55;color:#3d4260">${v}</div>
        </div>`).join("")}
    </div>
    ${problem.deadline?`<div style="margin-top:10px"><span class="badge badge-warn">⏱ Deadline: ${problem.deadline}</span></div>`:""}
  </div>

  <!-- 2. ISSUE SUMMARY -->
  <div class="section">
    <h2>2. Issue Landscape</h2>
    <div class="grid3" style="margin-bottom:10px">
      <div class="box box-grey" style="text-align:center">
        <div class="score-big" style="color:#0d0f18">${issues.length}</div>
        <div style="font-size:9px;color:#7b82a0;margin-top:3px">Total Issues</div>
      </div>
      <div class="box box-danger" style="text-align:center">
        <div class="score-big" style="color:#dc2626">${issues.filter(i=>i.severity==="Critical").length}</div>
        <div style="font-size:9px;color:#dc2626;margin-top:3px">Critical</div>
      </div>
      <div class="box box-warn" style="text-align:center">
        <div class="score-big" style="color:#d97706">${issues.filter(i=>i.severity==="High").length}</div>
        <div style="font-size:9px;color:#d97706;margin-top:3px">High Priority</div>
      </div>
    </div>
    <table>
      <thead><tr><th>Issue</th><th>Category</th><th>Severity</th><th>Owner</th></tr></thead>
      <tbody>
        ${issues.slice(0,12).map(i=>{
          const cat = (typeof ISSUE_CATEGORIES!=="undefined" ? ISSUE_CATEGORIES : []).find(c=>c.key===i.category);
          return `<tr>
            <td style="max-width:240px">${i.text}</td>
            <td><span class="badge badge-grey">${cat?cat.label:i.category||"--"}</span></td>
            <td><span class="badge ${i.severity==="Critical"?"badge-danger":i.severity==="High"?"badge-warn":"badge-grey"}">${i.severity}</span></td>
            <td style="color:#7b82a0">${i.owner||"--"}</td>
          </tr>`;
        }).join("")}
        ${issues.length>12?`<tr><td colspan="4" style="color:#9ca3af;font-style:italic">+ ${issues.length-12} more issues raised</td></tr>`:""}
      </tbody>
    </table>
  </div>

  <!-- 3. DECISION HIERARCHY -->
  <div class="section">
    <h2>3. Decision Hierarchy</h2>
    <div class="grid2">
      ${["given","focus","tactical","deferred","dependency"].map(tier=>{
        const td = decisions.filter(d=>d.tier===tier);
        if(!td.length) return "";
        const labels={"given":"Given Decisions","focus":"Focus Decisions","tactical":"Tactical Decisions","deferred":"Deferred","dependency":"Dependencies"};
        const colors={"given":"badge-grey","focus":"badge-blue","tactical":"badge-grey","deferred":"badge-green","dependency":"badge-warn"};
        return `<div>
          <div class="meta-label" style="margin-bottom:5px">${labels[tier]||tier} (${td.length})</div>
          ${td.map(d=>`<div style="margin-bottom:5px;padding:5px 8px;background:#f9fafb;border-radius:4px;border:1px solid #e5e7eb">
            <div style="font-weight:600;font-size:10px;margin-bottom:3px">${d.label}</div>
            <div style="display:flex;gap:4px;flex-wrap:wrap">${d.choices.slice(0,3).map(c=>`<span class="badge badge-grey">${c}</span>`).join("")}</div>
          </div>`).join("")}
        </div>`;
      }).join("")}
    </div>
  </div>

  <div class="page-break">

  <!-- 4. STRATEGY TABLE -->
  <h2 style="margin-bottom:12px">4. Strategy Table</h2>
  ${focusDecs.length>0&&strategies.length>0?`
  <table>
    <thead>
      <tr>
        <th>Decision</th>
        ${strategies.map((s,i)=>`<th style="color:${DS.s[s.colorIdx]?.fill||DS.accent}">${DS.sNames[s.colorIdx]||s.name}</th>`).join("")}
      </tr>
    </thead>
    <tbody>
      ${focusDecs.map(d=>`
        <tr>
          <td style="font-weight:600">${d.label}</td>
          ${strategies.map(s=>{
            const idx=s.selections?.[d.id];
            const col=DS.s[s.colorIdx];
            return `<td ${idx!==undefined?`style="background:${col?.soft};color:${col?.fill};font-weight:600"`:""}>${idx!==undefined?d.choices[idx]:"--"}</td>`;
          }).join("")}
        </tr>`).join("")}
    </tbody>
  </table>
  <div style="margin-top:10px;display:flex;gap:10px;flex-wrap:wrap">
    ${strategies.map((s,i)=>{
      const col=DS.s[s.colorIdx];
      const complete=focusDecs.filter(d=>s.selections?.[d.id]!==undefined).length;
      return `<div style="display:flex;align-items:center;gap:5px;padding:4px 10px;border-radius:4px;border:1px solid ${col?.line};background:${col?.soft}">
        <span class="strat-dot" style="background:${col?.fill}"></span>
        <span style="font-size:10px;font-weight:700;color:${col?.fill}">${DS.sNames[s.colorIdx]||s.name}</span>
        <span style="font-size:9px;color:#9ca3af">${complete}/${focusDecs.length} decisions</span>
        ${s.description?`<span style="font-size:9px;color:#7b82a0">· ${s.description.slice(0,50)}</span>`:""}
      </div>`;
    }).join("")}
  </div>` : `<div class="box box-grey">Strategy table not yet populated.</div>`}

  <!-- 5. QUALITATIVE ASSESSMENT -->
  <div class="section" style="margin-top:18px">
    <h2>5. Qualitative Assessment</h2>
    ${criteria.length>0&&strategies.length>0?`
    <table>
      <thead>
        <tr>
          <th>Criterion</th>
          ${strategies.map(s=>`<th style="color:${DS.s[s.colorIdx]?.fill}">${DS.sNames[s.colorIdx]||s.name}</th>`).join("")}
        </tr>
      </thead>
      <tbody>
        ${criteria.map(c=>`
          <tr>
            <td style="font-weight:600">${c.label}<div style="font-size:9px;color:#9ca3af;font-weight:400">${c.type}</div></td>
            ${strategies.map(s=>{
              const sc=assessmentScores[`${s.id}__${c.id}`]||0;
              const col=DS.s[s.colorIdx];
              const best=Math.max(...strategies.map(st=>assessmentScores[`${st.id}__${c.id}`]||0));
              return `<td style="text-align:center${sc===best&&sc>0?`;background:${col?.soft};color:${col?.fill};font-weight:700`:""}">
                ${sc>0?`${sc}/5`:"--"}
              </td>`;
            }).join("")}
          </tr>`).join("")}
        <tr style="background:#f4f5f8;font-weight:700">
          <td>Weighted Total</td>
          ${strategies.map(s=>{
            const p=pct(s);
            const col=DS.s[s.colorIdx];
            return `<td style="text-align:center;color:${col?.fill}">${p>0?`${p}%`:"--"}</td>`;
          }).join("")}
        </tr>
      </tbody>
    </table>` : `<div class="box box-grey">Qualitative assessment not yet completed.</div>`}
  </div>

  <div class="page-break">

  <!-- 6. DQ SCORECARD -->
  <h2 style="margin-bottom:12px">6. Decision Quality Scorecard</h2>
  <div class="grid2" style="margin-bottom:14px">
    <div class="box ${overall>=70?"box-green":overall>=45?"box-warn":"box-danger"}" style="text-align:center">
      <div class="score-big" style="color:${scoreColor(overall)}">${overall>0?overall:"--"}</div>
      <div style="font-size:9px;color:${scoreColor(overall)};margin-top:3px;font-weight:700;text-transform:uppercase;letter-spacing:.6px">Overall DQ Score</div>
      ${overall>0?`<div class="bar-track" style="margin-top:8px"><div class="bar-fill" style="width:${overall}%;background:${scoreColor(overall)}"></div></div>`:""}
    </div>
    <div style="display:flex;flex-direction:column;gap:5px;justify-content:center">
      ${DQ_ELEMENTS.map(el=>{
        const s=dqScores[el.key]||0;
        return `<div style="display:flex;align-items:center;gap:7px">
          <span style="font-size:11px;width:16px">${el.icon}</span>
          <span style="font-size:9px;font-weight:600;color:#3d4260;flex:1">${el.label}</span>
          <div class="bar-track" style="width:80px;flex-shrink:0"><div class="bar-fill" style="width:${s}%;background:${scoreColor(s)}"></div></div>
          <span style="font-size:10px;font-weight:700;color:${scoreColor(s)};width:24px;text-align:right">${s>0?s:"--"}</span>
        </div>`;
      }).join("")}
    </div>
  </div>

  ${narrative?.weakestLinkAnalysis?`
  <div class="box box-danger">
    <h3 style="color:#dc2626;margin-bottom:5px">Weakest Link</h3>
    <div>${narrative.weakestLinkAnalysis}</div>
  </div>`:""}

  <!-- 7. DECISION BRIEF -->
  ${brief?`
  <div class="section">
    <h2>7. Decision Brief</h2>
    ${brief.headline?`<div style="font-family:'Libre Baskerville',Georgia,serif;font-size:14px;font-style:italic;margin-bottom:10px;line-height:1.4">"${brief.headline}"</div>`:""}
    ${brief.situationSummary?`<p style="margin-bottom:10px;line-height:1.65;color:#3d4260">${brief.situationSummary}</p>`:""}
    ${brief.recommendedStrategyName?`
    <div class="box box-blue" style="margin-bottom:10px">
      <h3 style="color:#2563eb">Recommended Strategy</h3>
      <div style="font-size:13px;font-weight:700;margin-bottom:5px">${brief.recommendedStrategyName}</div>
      ${brief.recommendationRationale?`<div style="line-height:1.6">${brief.recommendationRationale}</div>`:""}
    </div>`:""}
    <div class="grid2">
      ${brief.keyTradeoff?`<div class="box box-warn"><h3 style="color:#d97706">Key Trade-off</h3><div>${brief.keyTradeoff}</div></div>`:""}
      ${brief.criticalAssumption?`<div class="box box-danger"><h3 style="color:#dc2626">Critical Assumption</h3><div>${brief.criticalAssumption}</div></div>`:""}
    </div>
  </div>`:""}

  <!-- 8. NEXT STEPS -->
  ${narrative?.priorityActions?.length?`
  <div class="section">
    <h2>8. Priority Actions</h2>
    <table>
      <thead><tr><th>#</th><th>Action</th><th>Element</th><th>Urgency</th></tr></thead>
      <tbody>
        ${narrative.priorityActions.map((a,i)=>`
          <tr>
            <td style="font-weight:700;color:#2563eb">${i+1}</td>
            <td>${a.action}</td>
            <td>${a.element||"--"}</td>
            <td><span class="badge ${a.urgency==="immediate"?"badge-danger":a.urgency==="before-deciding"?"badge-warn":"badge-green"}">${a.urgency}</span></td>
          </tr>`).join("")}
      </tbody>
    </table>
  </div>`:""}

  <!-- FOOTER -->
  <div class="footer">
    <span>Vantage DQ -- Decision Quality Platform</span>
    <span>${problem.projectCode||""} ${problem.projectName||""} ${problem.confidentiality?`· ${problem.confidentiality}`:""}</span>
    <span>Generated ${new Date().toLocaleDateString("en-GB",{day:"numeric",month:"long",year:"numeric"})}</span>
  </div>

</div>
</body>
</html>`;
}

function openPDF(content) {
  const win = window.open("", "_blank");
  if (win) { win.document.write(content); win.document.close(); }
}

