function OnboardingTooltip({ step, onNext, onSkip, totalSteps, currentStep }) {
  if (!step) return null;
  return (
    <div style={{ position:"fixed", inset:0, zIndex:500, pointerEvents:"none" }}>
      {/* Backdrop */}
      <div style={{ position:"absolute", inset:0, background:"rgba(0,0,0,.45)", pointerEvents:"auto" }}
        onClick={onSkip}/>
      {/* Tooltip card */}
      <div style={{
        position:"absolute",
        top:"50%", left:"50%",
        transform:"translate(-50%,-50%)",
        width:360, background:DS.canvas,
        borderRadius:12, padding:"22px 24px",
        boxShadow:"0 24px 60px rgba(0,0,0,.25)",
        border:`1px solid ${DS.canvasBdr}`,
        pointerEvents:"auto", zIndex:1,
        fontFamily:"'IBM Plex Sans','Helvetica Neue',sans-serif",
      }}>
        {/* Progress dots */}
        <div style={{ display:"flex", gap:5, marginBottom:14 }}>
          {Array.from({length:totalSteps}).map((_,i) => (
            <div key={i} style={{ height:3, flex:1, borderRadius:2,
              background: i<=currentStep ? DS.accent : DS.canvasBdr,
              transition:"background .2s" }}/>
          ))}
        </div>

        <div style={{ fontSize:10, fontWeight:700, color:DS.accent,
          letterSpacing:.8, textTransform:"uppercase", marginBottom:6 }}>
          {currentStep+1} of {totalSteps}
        </div>
        <div style={{ fontFamily:"'Libre Baskerville',Georgia,serif", fontSize:17,
          fontWeight:700, color:DS.ink, marginBottom:8, lineHeight:1.3 }}>
          {step.title}
        </div>
        <div style={{ fontSize:13, color:DS.inkSub, lineHeight:1.65, marginBottom:18 }}>
          {step.body}
        </div>
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center" }}>
          <button onClick={onSkip}
            style={{ background:"none", border:"none", cursor:"pointer",
              fontSize:12, color:DS.inkTer, fontFamily:"inherit" }}>
            Skip tour
          </button>
          <Btn variant="primary" onClick={onNext}>{step.action}</Btn>
        </div>
      </div>
    </div>
  );
}

function SessionHealthBar({ problem, issues, decisions, strategies, criteria, assessmentScores, dqScores, stakeholders, influenceNodes, scenarioData, voiItems }) {
  const items = [
    { label:"Frame",        done: problem.decisionStatement?.length > 20 },
    { label:"Issues",       done: issues.length >= 3 },
    { label:"Hierarchy",    done: decisions.filter(d=>d.tier==="focus").length > 0 && criteria.length > 0 },
    { label:"Strategies",   done: strategies.length >= 2 && strategies.some(s=>Object.keys(s.selections||{}).length>0) },
    { label:"Assessment",   done: Object.keys(assessmentScores).length > 0 },
    { label:"Scorecard",    done: Object.values(dqScores||{}).some(s=>s>0) },
    { label:"Stakeholders", done: (stakeholders||[]).length > 0 },
    { label:"Influence",    done: (influenceNodes||[]).length >= 3 },
    { label:"Scenarios",    done: (scenarioData?.scenarios||[]).length > 0 },
    { label:"VoI",          done: (voiItems||[]).some(x=>x.classification) },
  ];
  const score = Math.round((items.filter(i=>i.done).length / items.length) * 100);
  const color = score>=80 ? DS.success : score>=50 ? DS.warning : DS.accent;

  return (
    <div style={{ display:"flex", alignItems:"center", gap:8 }}>
      <div style={{ display:"flex", gap:3 }}>
        {items.map((item,i) => (
          <div key={i} title={item.label}
            style={{ width:16, height:4, borderRadius:2,
              background: item.done ? color : DS.border,
              transition:"background .3s" }}/>
        ))}
      </div>
      <span style={{ fontSize:10, fontWeight:700, color, minWidth:28 }}>{score}%</span>
    </div>
  );
}

/* ── TOOLS DROPDOWN ────────────────────────────────────────────────────────── */
function ToolsMenu({ onWorkshop, onVersions, onDqi, onDeepDive, onProject, onNew, onGameTheory, aiBusy }) {
  const [open, setOpen] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    const handleClick = (e) => {
      if (ref.current && !ref.current.contains(e.target)) setOpen(false);
    };
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, []);

  const items = [
    { icon:"♟", label:"Game Theory",       sub:"Strategic interaction analysis",  action:onGameTheory, highlight:false },
    { icon:"◌", label:"New Workspace",    sub:"Start a fresh decision",        action:onNew, highlight:true },
    { icon:"⊕", label:"AI Deep Dive",     sub:"Analyse a problem brief",      action:onDeepDive },
    { icon:"◉", label:"Workshop Mode",    sub:"Live facilitation view",        action:onWorkshop },
    { icon:"◷", label:"Version History",  sub:"Snapshots & restore",           action:onVersions },
    { icon:"◎", label:"DQi Dashboard",    sub:"Organisation performance",      action:onDqi },
    { icon:"◧", label:"Project Setup",    sub:"Identity & metadata",           action:onProject },
  ];

  return (
    <div ref={ref} style={{ position:"relative" }}>
      <button onClick={()=>setOpen(o=>!o)}
        style={{ padding:"5px 12px", border:`1px solid ${open?DS.accent:DS.border}`,
          borderRadius:6, background:open?DS.chromeMid:"transparent",
          color:open?DS.accent:DS.textSec, cursor:"pointer", fontSize:11,
          fontWeight:600, fontFamily:"inherit", display:"flex", alignItems:"center", gap:5,
          transition:"all .12s" }}>
        Tools
        <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round">
          <polyline points="6,9 12,15 18,9"/>
        </svg>
      </button>

      {open && (
        <div style={{ position:"absolute", top:"calc(100% + 6px)", right:0, width:220,
          background:DS.chromeAlt, border:`1px solid ${DS.border}`, borderRadius:9,
          boxShadow:"0 8px 32px rgba(0,0,0,.3)", zIndex:200, overflow:"hidden",
          animation:"fadeUp .15s ease" }}>
          {items.map((item,i) => (
            <button key={i}
              onClick={()=>{ item.action(); setOpen(false); }}
              style={{ width:"100%", padding:"10px 14px", background:"transparent",
                border:"none", borderBottom: i<items.length-1?`1px solid ${DS.border}`:"none",
                cursor:"pointer", display:"flex", alignItems:"center", gap:10,
                fontFamily:"inherit", textAlign:"left", transition:"background .1s" }}
              onMouseEnter={e=>e.currentTarget.style.background=DS.chromeMid}
              onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
              <span style={{ fontSize:14, flexShrink:0 }}>{item.icon}</span>
              <div>
                <div style={{ fontSize:12, fontWeight:600, color:DS.textSec }}>{item.label}</div>
                <div style={{ fontSize:10, color:DS.textTer }}>{item.sub}</div>
              </div>
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

/* ── MAIN APP ─────────────────────────────────────────────────────────────── */
function AppMain() {
  const [module, setModule]               = useState("problem");
  const [problem, setProblem]             = useState(defaultProblem);
  const [issues, setIssues]               = useState(defaultIssues);
  const [decisions, setDecisions]         = useState(defaultDecisions);
  const [criteria, setCriteria]           = useState(defaultCriteria);
  const [strategies, setStrategies]       = useState(defaultStrategies);
  const [assessmentScores, setAssessmentScores] = useState({});
  const [dqScores, setDqScores]           = useState({});
  const [brief, setBriefState]            = useState(null);
  const [narrative, setNarrativeState]    = useState(null);
  const [aiMessages, setAIMessages]       = useState([]);
  const [influenceNodes, setInfluenceNodes] = useState([]);
  const [influenceEdges, setInfluenceEdges] = useState([]);
  // Phase 2 lifted state
  const [scenarioData, setScenarioData]     = useState({
    uncertainties:[], axis1:null, axis2:null,
    scenarios:[], perfMatrix:{}, stressAnalysis:null, scenarioMode:null,
  });
  const [voiItems, setVoiItems]             = useState([]);
  const [timelineEvents, setTimelineEvents] = useState([]);
  const [stakeholders, setStakeholders]     = useState([]);

  // UI state
  const [showAI, setShowAI]               = useState(true);
  const [showQuickStart, setShowQuickStart] = useState(true);
  const [workshopOpen, setWorkshopOpen]   = useState(false);
  const [gameTheoryOpen, setGameTheoryOpen] = useState(false);

  // ── Auth & collaboration state ───────────────────────────────────────────
  const [currentUser, setCurrentUser]       = useState(null);
  const [authChecked, setAuthChecked]       = useState(false);
  const [presence, setPresence]             = useState([]);
  const [showComments, setShowComments]     = useState(false);
  const [notifications, setNotifications]   = useState([]);
  const [toastMsg, setToastMsg]             = useState(null);
  const [decisionId, setDecisionId]         = useState(null);
  const [syncStatus, setSyncStatus]         = useState("local"); // local | saving | saved | error
  const [showDecisions, setShowDecisions]   = useState(false);
  const [decisionList, setDecisionList]     = useState([]);
  const syncTimerRef = useRef(null);
  const [versionOpen, setVersionOpen]     = useState(false);
  const [dqiOpen, setDqiOpen]             = useState(false);
  const [projectSetupOpen, setProjectSetupOpen] = useState(false);
  const [navCollapsed, setNavCollapsed]   = useState(false);

  // Onboarding
  const [onboardingStep, setOnboardingStep] = useState(-1);

  const { busy: aiBusy, call: aiCall } = useAI();
  const pushAIMsg = (msg) => setAIMessages(m=>[...m, msg]);

  // Auto-save
  useEffect(() => {
    saveSession({ problem, issues, decisions, criteria, strategies, assessmentScores, dqScores });
  }, [problem, issues, decisions, criteria, strategies, assessmentScores, dqScores]);

  // ── Auth: check session on load + handle magic link callback ──────────────
  useEffect(() => {
    // Handle magic link token in URL hash
    const hash = window.location.hash;
    if (hash.includes("access_token=")) {
      const params = new URLSearchParams(hash.slice(1));
      const token = params.get("access_token");
      if (token) {
        sbExchangeToken(token).then(session => {
          if (session) {
            setCurrentUser(session.user);
            window.history.replaceState({}, "", window.location.pathname + window.location.search);
          }
          setAuthChecked(true);
        });
        return;
      }
    }
    // Check stored session
    sbGetSession().then(session => {
      if (session) setCurrentUser(session.user);
      setAuthChecked(true);
    });
  }, []);

  // ── Realtime: subscribe when decision loaded ───────────────────────────────
  useEffect(() => {
    if (!decisionId || !_SB_URL) return;
    const unsubscribe = sbSubscribe(decisionId, (msg) => {
      if (msg.topic?.includes("decisions")) {
        // Another user updated the decision
        const name = msg.payload?.new?.updated_by_name || "A teammate";
        showToast(name + " updated this decision");
        // Reload if we're not the one saving
        if (syncStatus !== "saving") {
          sbGet(decisionId).then(row => {
            if (row?.data) {
              const d = row.data;
              if (d.problem)          setProblem(d.problem);
              if (d.issues)           setIssues(d.issues);
              if (d.decisions)        setDecisions(d.decisions);
              if (d.criteria)         setCriteria(d.criteria);
              if (d.strategies)       setStrategies(d.strategies);
              if (d.assessmentScores) setAssessmentScores(d.assessmentScores);
              if (d.dqScores)         setDqScores(d.dqScores);
            }
          });
        }
      }
    });
    return unsubscribe;
  }, [decisionId]);

  // ── Toast helper ──────────────────────────────────────────────────────────
  const showToast = (msg) => {
    setToastMsg(msg);
    setTimeout(() => setToastMsg(null), 4000);
  };

  // ── Presence: broadcast current module ────────────────────────────────────
  // ── REALTIME PRESENCE via Supabase ──────────────────────────────────────
  // Writes current user's presence to the decision row every 15s.
  // Reads back all presence from the same row to show collaborators.
  useEffect(() => {
    if (!currentUser || !decisionId || !_SB_URL) return;
    const name = currentUser.user_metadata?.name || currentUser.email?.split("@")[0] || "Anonymous";
    const myId = currentUser.id;

    const writeAndRead = async () => {
      try {
        // Read current presence from DB
        const r = await fetch(
          _SB_URL + "/rest/v1/decisions?id=eq." + decisionId + "&select=presence",
          { headers: _sbHeaders() }
        );
        const rows = await r.json();
        const existing = (rows?.[0]?.presence) || {};

        // Write our presence
        const now = Date.now();
        existing[myId] = { id:myId, name, email:currentUser.email, module, lastSeen:now };

        // Remove stale entries (>45s)
        Object.keys(existing).forEach(k => {
          if (now - (existing[k].lastSeen||0) > 45000) delete existing[k];
        });

        // Patch presence back
        await fetch(
          _SB_URL + "/rest/v1/decisions?id=eq." + decisionId,
          { method:"PATCH", headers:_sbHeaders(), body:JSON.stringify({ presence: existing }) }
        );

        // Show all active users (including self)
        const active = Object.values(existing).filter(p => now - p.lastSeen < 45000);
        setPresence(active);
      } catch(e) {}
    };

    writeAndRead();
    const interval = setInterval(writeAndRead, 15000);

    // Clean up: remove our presence when leaving
    return () => {
      clearInterval(interval);
      if (!_SB_URL || !decisionId) return;
      fetch(
        _SB_URL + "/rest/v1/decisions?id=eq." + decisionId + "&select=presence",
        { headers: _sbHeaders() }
      ).then(r => r.json()).then(rows => {
        const existing = (rows?.[0]?.presence) || {};
        delete existing[myId];
        fetch(
          _SB_URL + "/rest/v1/decisions?id=eq." + decisionId,
          { method:"PATCH", headers:_sbHeaders(), body:JSON.stringify({ presence: existing }) }
        ).catch(()=>{});
      }).catch(()=>{});
    };
  }, [module, currentUser, decisionId]);


  // ── Cloud sync ────────────────────────────────────────────────────────────
  // Load from URL if ?d=ID is present
  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const urlId = params.get("d");
    if (urlId) {
      setSyncStatus("saving");
      sbGet(urlId).then(row => {
        if (row?.data) {
          const d = row.data;
          if (d.problem)          setProblem(d.problem);
          if (d.issues)           setIssues(d.issues);
          if (d.decisions)        setDecisions(d.decisions);
          if (d.criteria)         setCriteria(d.criteria);
          if (d.strategies)       setStrategies(d.strategies);
          if (d.assessmentScores) setAssessmentScores(d.assessmentScores);
          if (d.dqScores)         setDqScores(d.dqScores);
          setDecisionId(urlId);
          setShowQuickStart(false);
          setSyncStatus("saved");
        } else {
          setSyncStatus("error");
        }
      });
    }
  }, []);

  // Auto-save to cloud whenever key state changes (debounced 2s)
  useEffect(() => {
    if (!_SB_URL || !_SB_KEY) return;
    if (syncTimerRef.current) clearTimeout(syncTimerRef.current);
    syncTimerRef.current = setTimeout(async () => {
      setSyncStatus("saving");
      const payload = {
        project_name: problem.projectName || problem.decisionStatement?.slice(0,60) || "Untitled",
        data: {
          problem, issues, decisions, criteria, strategies,
          assessmentScores, dqScores, brief, narrative,
          stakeholders, scenarioData, voiItems, timelineEvents,
          influenceNodes, influenceEdges,
        },
        updated_at: new Date().toISOString(),
      };
      let row;
      if (decisionId) {
        row = await sbUpdate(decisionId, payload);
      } else {
        row = await sbCreate(payload);
        if (row?.id) {
          setDecisionId(row.id);
          const newUrl = window.location.pathname + "?d=" + row.id;
          window.history.replaceState({}, "", newUrl);
        }
      }
      setSyncStatus(row ? "saved" : "error");
    }, 2000);
    return () => clearTimeout(syncTimerRef.current);
  }, [problem, issues, decisions, criteria, strategies, assessmentScores, dqScores,
       stakeholders, scenarioData, voiItems, timelineEvents, influenceNodes, influenceEdges]);


  // Onboarding complete
  const finishOnboarding = () => {
    try { localStorage.setItem("vantage_onboarded","1"); } catch {}
    setOnboardingStep(-1);
  };

  // QuickStart complete handler
  const handleQuickStartComplete = (draft, accepted) => {
    if (accepted.frame && draft.frame) {
      setProblem(p => ({
        ...p,
        projectName:        draft.projectName || p.projectName,
        decisionStatement:  draft.frame.decisionStatement  || p.decisionStatement,
        context:            draft.frame.context             || p.context,
        background:         draft.frame.background          || p.background,
        trigger:            draft.frame.trigger             || p.trigger,
        symptoms:           draft.frame.symptoms            || p.symptoms,
        rootDecision:       draft.frame.rootDecision        || p.rootDecision,
        scopeIn:            draft.frame.scopeIn             || p.scopeIn,
        scopeOut:           draft.frame.scopeOut            || p.scopeOut,
        timeHorizon:        draft.frame.timeHorizon         || p.timeHorizon,
        deadline:           draft.frame.deadline            || p.deadline,
        owner:              draft.frame.owner               || p.owner,
        stakeholders:       draft.frame.stakeholders?.length
                              ? draft.frame.stakeholders.map(s=>({...s,id:uid("sh")}))
                              : p.stakeholders,
        constraints:        draft.frame.constraints         || p.constraints,
        assumptions:        draft.frame.assumptions         || p.assumptions,
        successCriteria:    draft.frame.successCriteria     || p.successCriteria,
        failureConsequences:draft.frame.failureConsequences || p.failureConsequences,
        urgency:            draft.frame.urgency             || p.urgency,
        importance:         draft.frame.importance          || p.importance,
      }));
    }
    if (accepted.issues && draft.issues?.length) {
      const typeToCategory = {
        "Risk":"uncertainty-external","Opportunity":"opportunity","Constraint":"constraint",
        "Assumption":"assumption","Stakeholder Concern":"stakeholder-concern",
        "Operational":"uncertainty-internal","Financial":"uncertainty-internal",
        "Technical":"uncertainty-internal","Strategic":"focus-decision",
        "Regulatory":"uncertainty-external","Data Gap":"information-gap",
        "Open Question":"information-gap","Dependency":"uncertainty-external",
      };
      setIssues(draft.issues.map(i => ({
        id:uid("iss"), text:i.text,
        category: i.category || typeToCategory[i.type] || "uncertainty-external",
        severity: i.severity || "Medium", status:"Open", owner:"", votes:0,
      })));
    }
    if (accepted.decisions && draft.decisions?.length) {
      setDecisions(draft.decisions.map(d => ({
        id:uid("d"), label:d.label, choices:d.choices||["Option A","Option B"],
        tier:d.tier||"focus", owner:d.owner||"", rationale:d.rationale||"", sourceId:null,
      })));
    }
    if (accepted.criteria && draft.criteria?.length) {
      setCriteria(draft.criteria.map(c => ({
        id:uid("cr"), label:c.label, type:c.type||"strategic",
        weight:c.weight||"medium", description:c.description||"",
      })));
    }
    if (accepted.strategies && draft.strategies?.length) {
      setStrategies(draft.strategies.map((s,i) => ({
        id:uid("s"), colorIdx:i%DS.s.length,
        name:s.name||DS.sNames[i]||`Strategy ${i+1}`,
        description:s.description||"", objective:s.objective||"",
        keyAssumptions:s.keyAssumption||"", selections:{}, rationale:{},
      })));
    }

    // ── NEW: Brutal truths + info gaps → issues ──────────────────────────────
    if (accepted.brutalTruths && draft.brutalTruths?.length) {
      setIssues(prev => {
        const existing = new Set(prev.map(i=>i.text));
        const newIssues = draft.brutalTruths
          .filter(bt => !existing.has(bt.text))
          .map(bt => ({
            id:uid("iss"), text:bt.text,
            category:"brutal-truth",
            severity:bt.severity||"High", status:"Open", owner:"", votes:0,
            source:bt.source||"",
          }));
        return [...prev, ...newIssues];
      });
    }
    if (accepted.infoGaps && draft.informationGaps?.length) {
      setIssues(prev => {
        const existing = new Set(prev.map(i=>i.text));
        const newIssues = draft.informationGaps
          .filter(ig => !existing.has(ig.text))
          .map(ig => ({
            id:uid("iss"), text:ig.text,
            category:"information-gap",
            severity:ig.severity||"High", status:"Open", owner:"", votes:0,
            source:ig.source||"",
          }));
        return [...prev, ...newIssues];
      });
    }

    // ── NEW: Stakeholders ────────────────────────────────────────────────────
    if (accepted.stakeholders && draft.stakeholders?.length) {
      setStakeholders(draft.stakeholders.map(sh => ({
        id:uid("sh"),
        name:sh.name||"Unnamed",
        role:sh.role||"",
        influence:sh.influence||"Medium",
        alignment:sh.alignment||"neutral",
        primaryConcern:sh.primaryConcern||"",
        mustAlign:sh.mustAlign||false,
        engagementActions:"",
        notes:sh.isInferred?"[AI inferred -- verify with team]":"",
      })));
    }

    // ── NEW: Uncertainties → seed scenarioData ───────────────────────────────
    if (accepted.uncertainties && draft.uncertainties?.length) {
      setScenarioData(prev => ({
        ...prev,
        uncertainties: draft.uncertainties.map(u => ({
          id:uid("u"),
          label:u.label||"",
          description:u.description||"",
          theme:"",
          impact:"High",
          uncertainty:"High",
          resolvable:u.resolvable||"partially",
          resolutionPath:u.resolutionPath||"",
        })),
      }));
    }

    // ── Influence Map ────────────────────────────────────────────────────────
    if (accepted.influence && draft.influenceNodes?.length) {
      setInfluenceNodes(draft.influenceNodes.map((n,i) => ({
        id: n.id || ("n"+i),
        label: n.label||"",
        type: n.type||"uncertainty",
        description: n.description||"",
        x: 120 + (i%4)*180,
        y: 80 + Math.floor(i/4)*140,
        notes: n.source ? "[Source: "+n.source+"]" : "",
      })));
      if (draft.influenceEdges?.length) {
        setInfluenceEdges(draft.influenceEdges.map((e,i) => ({
          id: "e"+i,
          source: e.source,
          target: e.target,
          label: e.label||"",
          strength: e.strength||"moderate",
        })));
      }
    }

    // ── Timeline events ──────────────────────────────────────────────────────
    if (accepted.timeline && draft.timelineEvents?.length) {
      setTimelineEvents(draft.timelineEvents.map((ev,i) => ({
        id: uid("ev"),
        title: ev.title||"",
        type: ev.type||"risk_event",
        timing: ev.timing||i+1,
        timingEnd: (ev.timing||i+1)+1,
        severity: ev.severity||"Medium",
        description: ev.description||"",
        trigger: ev.trigger||"",
        mitigation: ev.mitigation||"",
        gateCondition: ev.gateCondition||"",
        owner: ev.owner||"",
        status: "pending",
      })));
    }

    // ── VoI items ────────────────────────────────────────────────────────────
    if (accepted.voi && draft.voiItems?.length) {
      setVoiItems(draft.voiItems.map(v => ({
        id: uid("voi"),
        label: v.label||"",
        description: v.description||"",
        classification: v.classification||"do_later",
        action: v.action||"",
        timeToLearn: v.timeToLearn||"",
        costEstimate: v.costEstimate||"Medium",
        decisionPivot: v.decisionPivot||"",
        wouldChangeDecision: v.wouldChangeDecision||false,
        confidence: v.confidence||"medium",
      })));
    }

    // ── DQ Scorecard preliminary ─────────────────────────────────────────────
    if (accepted.scorecard && draft.dqScores) {
      const hasAnyScore = Object.values(draft.dqScores).some(s => s > 0);
      if (hasAnyScore) {
        setDqScores(prev => {
          const allZero = Object.values(prev).every(s => s===0);
          if (allZero) return draft.dqScores;
          return prev; // don't overwrite existing scores
        });
      }
    }

    setShowQuickStart(false);
    setModule("problem");

    const loadedSections = [
      accepted.frame && "frame",
      accepted.issues && `${(draft.issues?.length||0)+(draft.brutalTruths?.length||0)+(draft.informationGaps?.length||0)} issues`,
      accepted.decisions && "decisions",
      accepted.criteria && "criteria",
      accepted.strategies && "strategies",
      accepted.stakeholders && `${draft.stakeholders?.length||0} stakeholders`,
      accepted.uncertainties && `${draft.uncertainties?.length||0} uncertainties`,
      accepted.influence && `${draft.influenceNodes?.length||0} influence nodes`,
      accepted.timeline && `${draft.timelineEvents?.length||0} timeline events`,
      accepted.voi && `${draft.voiItems?.length||0} VoI items`,
      draft.gameTheorySignals?.hasStrategicInteraction && "game theory signals",
    ].filter(Boolean);

    const flagCount = draft.validationFlags?.length||0;
    pushAIMsg({ role:"ai", text:`Deep dive complete. Loaded: ${loadedSections.join(", ")}. ${flagCount > 0 ? flagCount+" validation flags -- review the DQ Scorecard section. " : ""}${draft.gameTheorySignals?.hasStrategicInteraction ? "Game Theory module recommended -- strategic interaction detected. " : ""}Review each module and refine with your team.` });
    try { if (!localStorage.getItem("vantage_onboarded")) setOnboardingStep(0); } catch {}
  };

  const handleAISend = (text) => {
    pushAIMsg({ role:"user", text });
    const ctx = `Project:"${problem.projectName||problem.decisionStatement}" | Module:${module} | Issues:${issues.length} | Focus:${decisions.filter(d=>d.tier==="focus").length} | Strategies:${strategies.length} | Criteria:${criteria.length}`;
    aiCall(`You are a DQ expert facilitator. Context: ${ctx}\n\nQuestion: "${text}"\n\nReply in 80 words or less. Plain text only.`,
      r => pushAIMsg({ role:"ai", text:(r._raw||r.error||(typeof r==="string"?r:JSON.stringify(r))).slice(0,300) })
    );
  };

  const moduleCompletion = (id) => {
    if (id==="problem")       return problem.decisionStatement?.length>20&&problem.owner?.length>2 ? 100 : 40;
    if (id==="issues")        return Math.min(100, issues.length*12);
    if (id==="hierarchy")     return decisions.filter(d=>d.tier==="focus").length>0&&criteria.length>0 ? 100 : decisions.filter(d=>d.tier==="focus").length>0 ? 60 : 0;
    if (id==="strategy")      return strategies.length>0&&strategies.some(s=>Object.keys(s.selections||{}).length>0) ? 100 : 20;
    if (id==="assessment")    return Object.keys(assessmentScores).length>0 ? 100 : 0;
    if (id==="scorecard")     return Object.values(dqScores).some(s=>s>0) ? 100 : 0;
    if (id==="stakeholders")  return stakeholders.length>=2 ? 100 : stakeholders.length>0 ? 40 : 0;
    if (id==="export")        return brief||narrative ? 100 : 0;
    if (id==="influence")     return influenceNodes.length>=3 ? 100 : influenceNodes.length>0 ? 50 : 0;
    if (id==="scenarios")     return (scenarioData.scenarios||[]).length>0 ? 100 : (scenarioData.uncertainties||[]).length>0 ? 40 : 0;
    if (id==="voi")           return voiItems.some(x=>x.classification) ? 100 : voiItems.length>0 ? 40 : 0;
    if (id==="timeline")      return timelineEvents.length>0 ? 100 : 0;
    return 0;
  };

  const overall = Math.round(MODULES.filter(m=>m.id!=="influence").reduce((s,m)=>s+moduleCompletion(m.id),0)/PHASE1.length);

  // PDF export
  const handlePDFExport = () => {
    const html = buildPDFContent(problem, issues, decisions, strategies, criteria,
      assessmentScores, dqScores, brief, narrative);
    openPDF(html);
  };

  const moduleProps = {
    problem:      { data:problem, onChange:setProblem, aiCall, aiBusy, messages:aiMessages, onAIMsg:pushAIMsg, onAISend:handleAISend },
    issues:       { issues, onChange:setIssues, decisions, onDecisions:setDecisions, criteria, onCriteria:setCriteria, problem, aiCall, aiBusy, onAIMsg:pushAIMsg },
    hierarchy:    { decisions, criteria, onDecisions:setDecisions, onCriteria:setCriteria, issues, aiCall, aiBusy, onAIMsg:pushAIMsg },
    strategy:     { decisions, strategies, onChange:setStrategies, onDecisions:setDecisions, aiCall, aiBusy, problem, onAIMsg:pushAIMsg },
    assessment:   { strategies, decisions, criteria, problem, scores:assessmentScores, onScores:setAssessmentScores, aiCall, aiBusy, onAIMsg:pushAIMsg },
    scorecard:    { problem, issues, decisions, strategies, criteria, assessmentScores, brief, scores:dqScores, onScores:setDqScores, stakeholders, scenarioData, voiItems, aiCall, aiBusy, onAIMsg:pushAIMsg },
    stakeholders: { strategies, decisions, problem, issues, stakeholders, onChange:setStakeholders, aiCall, aiBusy, onAIMsg:pushAIMsg },
    export:       { problem, issues, decisions, criteria, strategies, assessmentScores, dqScores, brief, narrative, stakeholders, scenarioData, voiItems, timelineEvents, aiCall, aiBusy, onAIMsg:pushAIMsg },
    influence:    { issues, decisions, strategies, aiCall, aiBusy, onAIMsg:pushAIMsg, problem, onNodesChange:setInfluenceNodes, onEdgesChange:setInfluenceEdges },
    scenarios:    { strategies, decisions, issues, problem, nodes:influenceNodes, edges:influenceEdges, scenarioData, onScenarioData:setScenarioData, aiCall, aiBusy, onAIMsg:pushAIMsg },
    voi:          { nodes:influenceNodes, edges:influenceEdges, issues, strategies, decisions, problem, voiItems, onVoiItems:setVoiItems, aiCall, aiBusy, onAIMsg:pushAIMsg },
    timeline:     { decisions, strategies, issues, problem, nodes:influenceNodes, timelineEvents, onTimelineEvents:setTimelineEvents, aiCall, aiBusy, onAIMsg:pushAIMsg },
  };

  return (
    <div style={{ display:"flex", height:"100vh", background:DS.chrome, overflow:"hidden",
      fontFamily:"'IBM Plex Sans','Helvetica Neue',sans-serif", color:DS.textPri }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=IBM+Plex+Sans:wght@400;500;600;700&family=Libre+Baskerville:ital,wght@0,700;1,400&display=swap');
        *{box-sizing:border-box;margin:0;padding:0}
        ::-webkit-scrollbar{width:5px;height:5px}
        ::-webkit-scrollbar-track{background:transparent}
        ::-webkit-scrollbar-thumb{background:${DS.border};border-radius:3px}
        ::-webkit-scrollbar-thumb:hover{background:${DS.borderMid}}
        input,textarea,button,select{font-family:inherit}
        @keyframes aipulse{0%,100%{opacity:.2;transform:scale(.7)}50%{opacity:1;transform:scale(1)}}
        @keyframes slideIn{from{opacity:0;transform:translateX(-6px)}to{opacity:1;transform:translateX(0)}}
        @keyframes fadeUp{from{opacity:0;transform:translateY(6px)}to{opacity:1;transform:translateY(0)}}
        @keyframes fadeIn{from{opacity:0}to{opacity:1}}
        body{background:#252d3d}
        @media (max-width:900px){
          .nav-rail{width:52px!important}
          .nav-label{display:none!important}
          .nav-sub{display:none!important}
          .top-breadcrumb{display:none!important}
          .ai-panel-wrap{display:none!important}
        }
        @media (max-width:640px){
          .module-padding{padding:14px 16px!important}
          .grid-2col{grid-template-columns:1fr!important}
          .strategy-grid{grid-template-columns:1fr!important}
        }
      `}</style>

      {/* ── Auth gate ── */}
      {authChecked && !currentUser && _SB_URL && (
        <LoginScreen onLogin={(session)=>setCurrentUser(session.user)}/>
      )}

      {/* ── Toast notification ── */}
      {toastMsg && (
        <div style={{ position:"fixed", bottom:24, right:24, zIndex:999,
          padding:"10px 16px", borderRadius:8, fontSize:12, fontWeight:600,
          background:"#1e293b", color:"#f1f5f9",
          boxShadow:"0 8px 24px rgba(0,0,0,.3)",
          display:"flex", alignItems:"center", gap:8,
          animation:"fadeUp .2s ease" }}>
          <span>🔔</span> {toastMsg}
        </div>
      )}

      {/* Quick Start */}
      {showQuickStart && (
        <QuickStartScreen onComplete={handleQuickStartComplete} onSkip={(mode)=>{
          setShowQuickStart(false);
          if (mode === "clean") {
            setProblem({ id: uid("prob"), decisionStatement:"", context:"", owner:"", deadline:"",
              successCriteria:"", scopeIn:"", scopeOut:"", projectName:"", projectCode:"",
              client:"", sector:"", facilitator:"", sessionDate:"", decisionType:"",
              confidentiality:"Internal", stakeholders:[], constraints:[], assumptions:[] });
            setIssues([]);
            setDecisions([]);
            setCriteria([]);
            setStrategies([]);
            setAssessmentScores({});
            setDqScores({});
            setAIMessages([]);
            setModule("problem");
            try { localStorage.removeItem(SESSION_KEY); } catch(e) {}
          }
        }}/>
      )}

      {/* Onboarding */}
      {onboardingStep >= 0 && onboardingStep < ONBOARDING_STEPS.length && (
        <OnboardingTooltip
          step={ONBOARDING_STEPS[onboardingStep]}
          currentStep={onboardingStep}
          totalSteps={ONBOARDING_STEPS.length}
          onNext={()=>{ if(onboardingStep>=ONBOARDING_STEPS.length-1) finishOnboarding(); else setOnboardingStep(s=>s+1); }}
          onSkip={finishOnboarding}
        />
      )}

      {/* ── NAVIGATION RAIL ── */}
      <div className="nav-rail" style={{ width: navCollapsed?52:228,
        background:DS.chromeAlt, borderRight:`1px solid ${DS.border}`,
        display:"flex", flexDirection:"column", flexShrink:0,
        transition:"width .2s ease", overflow:"hidden" }}>

        {/* Logo + collapse toggle */}
        <div style={{ padding:"16px 14px 14px", borderBottom:`1px solid ${DS.border}`,
          display:"flex", alignItems:"center", gap:10 }}>
          <div style={{ width:28, height:28, borderRadius:6, background:DS.accent,
            display:"flex", alignItems:"center", justifyContent:"center", flexShrink:0,
            cursor:"pointer" }} onClick={()=>setNavCollapsed(c=>!c)}>
            <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round">
              <polygon points="12,2 22,8.5 22,15.5 12,22 2,15.5 2,8.5"/>
              <line x1="12" y1="2" x2="12" y2="22"/>
              <line x1="2" y1="8.5" x2="22" y2="8.5"/>
              <line x1="2" y1="15.5" x2="22" y2="15.5"/>
            </svg>
          </div>
          {!navCollapsed && (
            <div className="nav-label">
              <div style={{ fontSize:13, fontWeight:700, color:DS.textPri, letterSpacing:-.2 }}>Vantage DQ</div>
              <div style={{ fontSize:8, color:DS.textTer, letterSpacing:1.5, textTransform:"uppercase" }}>Decision Platform</div>
            </div>
          )}
        </div>

        {/* User info */}
        {!navCollapsed && currentUser && (
          <div style={{ padding:"8px 14px", borderBottom:`1px solid ${DS.border}`,
            display:"flex", alignItems:"center", gap:8 }}>
            <div style={{ width:24, height:24, borderRadius:"50%",
              background:"linear-gradient(135deg,#2563eb,#7c3aed)",
              display:"flex", alignItems:"center", justifyContent:"center",
              fontSize:10, fontWeight:700, color:"#fff", flexShrink:0 }}>
              {(currentUser.user_metadata?.name || currentUser.email||"?").slice(0,2).toUpperCase()}
            </div>
            <div style={{ flex:1, minWidth:0 }}>
              <div style={{ fontSize:11, fontWeight:600, color:DS.textPri,
                overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                {currentUser.user_metadata?.name || currentUser.email?.split("@")[0] || "Anonymous"}
              </div>
              <div style={{ fontSize:9, color:DS.textTer, overflow:"hidden",
                textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                {currentUser.id?.startsWith("guest_") ? "Guest" :
                 currentUser.email ? currentUser.email : "Signed in"}
              </div>
            </div>
            {!currentUser.id?.startsWith("guest_") && (
              <button onClick={()=>{ sbSignOut(); setCurrentUser(null); }}
                style={{ fontSize:9, color:DS.textTer, background:"none",
                  border:"none", cursor:"pointer", fontFamily:"inherit" }}>
                Sign out
              </button>
            )}
          </div>
        )}

        {/* Presence bar */}
        {!navCollapsed && presence.length > 1 && (
          <div style={{ padding:"6px 14px", borderBottom:`1px solid ${DS.border}` }}>
            <div style={{ fontSize:8, color:DS.textTer, textTransform:"uppercase",
              letterSpacing:.5, marginBottom:4 }}>Online</div>
            <PresenceBar presence={presence}/>
          </div>
        )}

        {/* Sync status + Share + Open */}
        {!navCollapsed && (
          <div style={{ padding:"8px 14px", borderBottom:`1px solid ${DS.border}`,
            display:"flex", flexDirection:"column", gap:6 }}>

            {/* Sync status */}
            <div style={{ display:"flex", alignItems:"center", gap:5 }}>
              <div style={{ width:6,height:6,borderRadius:"50%",flexShrink:0,
                background:_SB_URL
                  ? (syncStatus==="saved"?"#22c55e":syncStatus==="saving"?"#f59e0b":syncStatus==="error"?"#dc2626":"#6b7280")
                  : "#6b7280" }}/>
              <span style={{ fontSize:9, color:DS.textTer, flex:1 }}>
                {_SB_URL
                  ? (syncStatus==="saved"?"Synced to cloud":syncStatus==="saving"?"Saving…":syncStatus==="error"?"Sync error":"Local only")
                  : "Saved locally"}
              </span>
            </div>

            {/* Share + Open */}
            <div style={{ display:"flex", gap:6 }}>
              <button
                onClick={()=>{
                  const url = window.location.origin + window.location.pathname +
                    (decisionId ? "?d=" + decisionId : "");
                  navigator.clipboard.writeText(url)
                    .then(()=>showToast("Link copied -- share with your team"))
                    .catch(()=>showToast("Copy failed -- copy the URL from your browser"));
                }}
                style={{ flex:1, fontSize:10, fontWeight:700, fontFamily:"inherit",
                  padding:"6px 8px", border:`1px solid ${DS.border}`,
                  borderRadius:6, background:DS.chromeSub, color:DS.textSec,
                  cursor:"pointer", display:"flex", alignItems:"center",
                  justifyContent:"center", gap:4, transition:"all .12s" }}
                onMouseEnter={e=>{e.currentTarget.style.borderColor=DS.accent;e.currentTarget.style.color="#93c5fd";}}
                onMouseLeave={e=>{e.currentTarget.style.borderColor=DS.border;e.currentTarget.style.color=DS.textSec;}}>
                🔗 Share
              </button>
              <button
                onClick={async ()=>{
                  if (_SB_URL) {
                    const list = await sbList();
                    setDecisionList(list||[]);
                  } else {
                    setDecisionList([]);
                  }
                  setShowDecisions(d=>!d);
                }}
                style={{ flex:1, fontSize:10, fontWeight:700, fontFamily:"inherit",
                  padding:"6px 8px", border:`1px solid ${DS.border}`,
                  borderRadius:6, background:DS.chromeSub, color:DS.textSec,
                  cursor:"pointer", display:"flex", alignItems:"center",
                  justifyContent:"center", gap:4, transition:"all .12s" }}
                onMouseEnter={e=>{e.currentTarget.style.borderColor="#7c3aed";e.currentTarget.style.color="#a78bfa";}}
                onMouseLeave={e=>{e.currentTarget.style.borderColor=DS.border;e.currentTarget.style.color=DS.textSec;}}>
                📂 Open
              </button>
            </div>
          </div>
        )}
        {/* Project card */}
        {!navCollapsed && (
          <button onClick={()=>setProjectSetupOpen(true)}
            style={{ padding:"11px 16px", borderBottom:`1px solid ${DS.border}`,
              background:"transparent", border:"none", borderBottom:`1px solid ${DS.border}`,
              cursor:"pointer", textAlign:"left", width:"100%", transition:"background .12s" }}
            onMouseEnter={e=>e.currentTarget.style.background=DS.chromeMid}
            onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
            <div style={{ fontSize:8, color:DS.textTer, letterSpacing:1.2,
              textTransform:"uppercase", marginBottom:4 }}>Active Project</div>
            <div style={{ fontSize:11, fontWeight:700, color:DS.textPri, lineHeight:1.4,
              fontFamily:"'Libre Baskerville',Georgia,serif", marginBottom:4,
              wordBreak:"break-word", whiteSpace:"normal" }}>
              {problem.projectName || problem.decisionStatement || "Untitled"}
            </div>
            <div style={{ display:"flex", gap:5, flexWrap:"wrap" }}>
              {problem.projectCode && (
                <span style={{ fontSize:8, fontWeight:700, padding:"1px 5px", borderRadius:3,
                  background:DS.chromeSub, color:DS.textTer, border:`1px solid ${DS.border}` }}>
                  {problem.projectCode}
                </span>
              )}
              {problem.sector && (
                <span style={{ fontSize:8, fontWeight:700, padding:"1px 5px", borderRadius:3,
                  background:DS.accentSoft, color:DS.accent, border:`1px solid ${DS.accentLine}` }}>
                  {problem.sector.split("/")[0].trim()}
                </span>
              )}
              {problem.confidentiality && problem.confidentiality!=="Internal" && (
                <span style={{ fontSize:8, fontWeight:700, padding:"1px 5px", borderRadius:3,
                  background:DS.warnSoft, color:DS.warning, border:`1px solid ${DS.warnLine}` }}>
                  {problem.confidentiality}
                </span>
              )}
            </div>
            {problem.facilitator && (
              <div style={{ fontSize:9, color:DS.textTer, marginTop:4 }}>
                {problem.facilitator}{problem.sessionDate ? ` · ${new Date(problem.sessionDate).toLocaleDateString("en-GB",{day:"numeric",month:"short"})}` : ""}
              </div>
            )}
          </button>
        )}

        {/* Navigation */}
        <nav style={{ flex:1, overflowY:"auto", padding:"8px 0" }}>
          {/* Phase 1 */}
          {!navCollapsed && (
            <div style={{ fontSize:8, color:DS.textTer, letterSpacing:1.5,
              textTransform:"uppercase", padding:"6px 16px 3px", fontWeight:700 }}>
              Phase 1 -- Framing
            </div>
          )}
          {PHASE1.map((m) => {
            const active = module===m.id;
            const comp   = moduleCompletion(m.id);
            const done   = comp===100;
            return (
              <button key={m.id} onClick={()=>setModule(m.id)} title={navCollapsed?m.label:undefined}
                style={{ width:"100%", padding: navCollapsed?"10px 0":"8px 16px",
                  background:active?DS.chromeMid:"transparent", border:"none",
                  borderLeft:`3px solid ${active?DS.accent:"transparent"}`,
                  cursor:"pointer", display:"flex", alignItems:"center",
                  gap:navCollapsed?0:10, justifyContent:navCollapsed?"center":"flex-start",
                  transition:"all .12s",
                  animation:active?"slideIn .2s ease":undefined }}>
                <div style={{ width:22, height:22, borderRadius:5, flexShrink:0,
                  background:done?DS.success:active?DS.accent:DS.chromeSub,
                  border:`1px solid ${done?DS.successLine:active?DS.accentDim:DS.border}`,
                  display:"flex", alignItems:"center", justifyContent:"center", fontSize:10 }}>
                  {done
                    ? <Svg path={ICONS.check} size={11} color="#fff" sw={2.5}/>
                    : <span style={{ color:active?"#fff":DS.textTer, fontSize:8, fontWeight:700 }}>{m.num}</span>
                  }
                </div>
                {!navCollapsed && (
                  <div style={{ textAlign:"left", flex:1, minWidth:0 }}>
                    <div className="nav-label" style={{ fontSize:11, fontWeight:600,
                      color:active?DS.textPri:done?DS.textSec:DS.textTer }}>{m.label}</div>
                    <div className="nav-sub" style={{ fontSize:9, color:DS.textTer, marginTop:1 }}>{m.sub}</div>
                  </div>
                )}
                {!navCollapsed && (
                  <div style={{ width:5, height:5, borderRadius:"50%", flexShrink:0,
                    background:comp===100?DS.success:comp>0?DS.warning:DS.border }}/>
                )}
              </button>
            );
          })}

          {/* Phase 2 */}
          {!navCollapsed && (
            <div style={{ fontSize:8, color:DS.textTer, letterSpacing:1.5,
              textTransform:"uppercase", padding:"10px 16px 3px", fontWeight:700,
              borderTop:`1px solid ${DS.border}`, marginTop:4 }}>
              Phase 2 -- Analysis
            </div>
          )}
          {PHASE2.map((m) => {
            const active = module===m.id;
            return (
              <button key={m.id} onClick={()=>setModule(m.id)} title={navCollapsed?m.label:undefined}
                style={{ width:"100%", padding:navCollapsed?"10px 0":"8px 16px",
                  background:active?DS.chromeMid:"transparent", border:"none",
                  borderLeft:`3px solid ${active?DS.accent:"transparent"}`,
                  cursor:"pointer", display:"flex", alignItems:"center",
                  gap:navCollapsed?0:10, justifyContent:navCollapsed?"center":"flex-start",
                  transition:"all .12s" }}>
                {(() => {
                  const comp2 = moduleCompletion(m.id);
                  const done2 = comp2 === 100;
                  return (
                    <div style={{ width:22, height:22, borderRadius:5, flexShrink:0,
                      background:done2?DS.success:active?DS.accent:DS.chromeSub,
                      border:`1px solid ${done2?DS.successLine:active?DS.accentDim:DS.border}`,
                      display:"flex", alignItems:"center", justifyContent:"center", fontSize:10 }}>
                      {done2
                        ? <Svg path={ICONS.check} size={11} color="#fff" sw={2.5}/>
                        : <span style={{ color:active?"#fff":DS.textTer, fontSize:8, fontWeight:700 }}>{m.num}</span>
                      }
                    </div>
                  );
                })()}
                {!navCollapsed && (
                  <div style={{ textAlign:"left", flex:1, minWidth:0 }}>
                    <div className="nav-label" style={{ fontSize:11, fontWeight:600,
                      color:active?DS.textPri:DS.textTer }}>{m.label}</div>
                    <div className="nav-sub" style={{ fontSize:9, color:DS.textTer, marginTop:1 }}>{m.sub}</div>
                  </div>
                )}
                {!navCollapsed && (() => {
                  const comp2 = moduleCompletion(m.id);
                  return (
                    <div style={{ width:5, height:5, borderRadius:"50%", flexShrink:0,
                      background:comp2===100?DS.success:comp2>0?DS.warning:DS.border }}/>
                  );
                })()}
              </button>
            );
          })}
        </nav>

        {/* Session Snapshot */}
        {!navCollapsed && (
          <div style={{ padding:"10px 14px", borderTop:`1px solid ${DS.border}`,
            marginTop:"auto" }}>
            <div style={{ fontSize:7, color:DS.textTer, letterSpacing:1.2,
              textTransform:"uppercase", fontWeight:700, marginBottom:6 }}>Session</div>
            <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:5, marginBottom:8 }}>
              {[
                { label:"Issues",    value:issues.length,                              color:DS.accent },
                { label:"Decisions", value:decisions.filter(d=>d.tier==="focus").length, color:"#7c3aed" },
                { label:"Strategies",value:strategies.length,                          color:"#059669" },
                { label:"Criteria",  value:criteria.length,                            color:"#d97706" },
              ].map(tile=>(
                <div key={tile.label} style={{ padding:"5px 7px",
                  background:DS.chromeSub, borderRadius:5,
                  border:`1px solid ${DS.border}` }}>
                  <div style={{ fontSize:14, fontWeight:700, color:tile.color,
                    fontFamily:"'Libre Baskerville',serif", lineHeight:1 }}>{tile.value}</div>
                  <div style={{ fontSize:8, color:DS.textTer, marginTop:2 }}>{tile.label}</div>
                </div>
              ))}
            </div>
            <div style={{ height:3, background:DS.chromeMid, borderRadius:2, overflow:"hidden", marginBottom:4 }}>
              <div style={{ height:"100%", borderRadius:2, transition:"width .5s",
                background:`linear-gradient(90deg, ${DS.accent}, #60a5fa)`,
                width:`${overall}%` }}/>
            </div>
            <div style={{ display:"flex", justifyContent:"space-between" }}>
              <span style={{ fontSize:8, color:DS.textTer }}>Progress</span>
              <span style={{ fontSize:8, color:DS.textSec, fontWeight:700 }}>{overall}%</span>
            </div>
          </div>
        )}
      </div>

      {/* ── MAIN CONTENT ── */}
      <div style={{ flex:1, display:"flex", flexDirection:"column", minWidth:0, overflow:"hidden" }}>

        {/* API key warning */}
        {false && (
          <div style={{ padding:"8px 16px", background:"#7c3aed22", borderBottom:"1px solid #7c3aed44",
            display:"flex", alignItems:"center", gap:8, flexShrink:0, fontSize:11, color:"#a78bfa" }}>
            <span>⚠</span>
            <span><strong>API key not configured.</strong> Create a <code style={{background:"#1c2030",padding:"1px 5px",borderRadius:3}}>.env</code> file in your project root with <code style={{background:"#1c2030",padding:"1px 5px",borderRadius:3}}>VITE_ANTHROPIC_API_KEY=your_key</code> then restart <code style={{background:"#1c2030",padding:"1px 5px",borderRadius:3}}>npm run dev</code>.</span>
          </div>
        )}
        {/* ── TOP BAR ── */}
        <div style={{ height:46, background:DS.chromeAlt, borderBottom:`1px solid ${DS.border}`,
          display:"flex", alignItems:"center", padding:"0 16px", gap:8, flexShrink:0 }}>

          {/* Breadcrumb */}
          <div className="top-breadcrumb" style={{ flex:1, display:"flex", alignItems:"center", gap:6, minWidth:0 }}>
            <span style={{ fontSize:10, color:DS.textTer, fontWeight:600, letterSpacing:.3 }}>
              {MODULES.find(m=>m.id===module)?.icon}
            </span>
            <span style={{ fontSize:11, fontWeight:700, color:DS.textPri, whiteSpace:"nowrap" }}>
              {MODULES.find(m=>m.id===module)?.label}
            </span>
            {problem.projectName && (
              <>
                <span style={{ color:DS.textTer, fontSize:12 }}>/</span>
                <span style={{ fontSize:10, color:DS.textTer, overflow:"hidden",
                  textOverflow:"ellipsis", whiteSpace:"nowrap", maxWidth:200 }}>
                  {problem.projectName}
                </span>
              </>
            )}
          </div>

          {/* Session health */}
          <SessionHealthBar problem={problem} issues={issues} decisions={decisions}
            strategies={strategies} criteria={criteria} assessmentScores={assessmentScores}
            dqScores={dqScores} stakeholders={stakeholders} influenceNodes={influenceNodes} scenarioData={scenarioData} voiItems={voiItems}/>

          {/* Right controls */}
          <div style={{ display:"flex", gap:6, alignItems:"center" }}>
            {aiBusy && (
              <div style={{ display:"flex", alignItems:"center", gap:4, fontSize:10, color:DS.accent }}>
                <div style={{ width:5,height:5,borderRadius:"50%",background:DS.accent,
                  animation:"aipulse 1s infinite" }}/>
                AI…
              </div>
            )}

            {/* PDF Export */}
            <button onClick={handlePDFExport}
              style={{ padding:"5px 11px", border:`1px solid ${DS.border}`, borderRadius:6,
                background:"transparent", color:DS.textTer, cursor:"pointer", fontSize:11,
                fontWeight:600, fontFamily:"inherit", display:"flex", alignItems:"center", gap:5,
                transition:"all .12s" }}
              onMouseEnter={e=>{e.currentTarget.style.borderColor="#22c55e";e.currentTarget.style.color="#22c55e";}}
              onMouseLeave={e=>{e.currentTarget.style.borderColor=DS.border;e.currentTarget.style.color=DS.textTer;}}>
              <Svg path={ICONS.export} size={12} color="currentColor"/> PDF
            </button>

            {/* Cross-Module AI */}
            <CrossModuleAI problem={problem} issues={issues} decisions={decisions}
              criteria={criteria} strategies={strategies}
              assessmentScores={assessmentScores} dqScores={dqScores}
              nodes={influenceNodes} edges={influenceEdges}
              stakeholders={stakeholders} scenarioData={scenarioData}
              voiItems={voiItems} timelineEvents={timelineEvents}
              aiCall={aiCall} aiBusy={aiBusy} onAIMsg={pushAIMsg}/>

            {/* Tools dropdown */}
            <ToolsMenu
              onDeepDive={()=>setShowQuickStart(true)}
              onWorkshop={()=>setWorkshopOpen(true)}
              onVersions={()=>setVersionOpen(true)}
              onDqi={()=>setDqiOpen(true)}
              onProject={()=>setProjectSetupOpen(true)}
              onNew={()=>setShowQuickStart(true)}
              onGameTheory={()=>setGameTheoryOpen(true)}
              aiBusy={aiBusy}/>

            {/* Co-Pilot toggle */}
            <button onClick={()=>setShowAI(a=>!a)}
              style={{ padding:"5px 11px", border:`1px solid ${showAI?DS.accent:DS.border}`,
                borderRadius:6, background:showAI?DS.chromeMid:"transparent",
                color:showAI?DS.accent:DS.textSec, cursor:"pointer", fontSize:11,
                fontWeight:600, display:"flex", alignItems:"center", gap:5,
                fontFamily:"inherit" }}>
              <Svg path={ICONS.spark} size={12} color="currentColor"/> Co‑Pilot
            </button>
          </div>
        </div>

        {/* ── MODULE + AI PANEL ── */}
        <div style={{ flex:1, display:"flex", overflow:"hidden" }}>

          {/* Active module */}
          <div style={{ flex:1, background:DS.canvasAlt, overflow:"hidden",
            display:"flex", flexDirection:"column",
            animation:"fadeIn .2s ease" }} key={module}>
            <NudgeBar module={module} problem={problem} issues={issues} strategies={strategies} decisions={decisions}/>
            {/* Comments toggle */}
            {decisionId && (
              <button onClick={()=>setShowComments(s=>!s)}
                style={{ position:"absolute", right:12, top:"50%",
                  transform:"translateY(-50%)",
                  padding:"4px 10px", fontSize:10, fontWeight:700,
                  fontFamily:"inherit", border:`1px solid ${DS.border}`,
                  borderRadius:5, background:showComments?DS.accentSoft:"transparent",
                  color:showComments?DS.accent:DS.textTer, cursor:"pointer",
                  display:"flex", alignItems:"center", gap:4 }}>
                💬 Comments
              </button>
            )}
            {module==="problem"       && <ModuleProblemDefinition    {...moduleProps.problem}/>}
            {module==="issues"        && <ModuleIssueRaising         {...moduleProps.issues}/>}
            {module==="hierarchy"     && <ModuleDecisionHierarchy    {...moduleProps.hierarchy}/>}
            {module==="strategy"      && <ModuleStrategyTable        {...moduleProps.strategy}/>}
            {module==="assessment"    && <ModuleQualitativeAssessment {...moduleProps.assessment}/>}
            {module==="scorecard"     && <ModuleDQScorecard          {...moduleProps.scorecard}/>}
            {module==="stakeholders"  && <ModuleStakeholders         {...moduleProps.stakeholders}/>}
            {module==="export"        && <ModuleExport               {...moduleProps.export}/>}
            {module==="influence"     && <ModuleInfluenceMap         {...moduleProps.influence}/>}
            {module==="scenarios"     && <ModuleScenarios            {...moduleProps.scenarios}/>}
            {module==="voi"           && <ModuleVoI                  {...moduleProps.voi}/>}
            {module==="timeline"      && <ModuleTimeline       {...moduleProps.timeline}/>}
          </div>

          {/* Co-Pilot */}
          {showAI && (
            <div className="ai-panel-wrap" style={{ width:268, flexShrink:0,
              display:"flex", flexDirection:"column", overflow:"hidden" }}>
              <AIPanel messages={aiMessages} onSend={handleAISend}
                loading={aiBusy} nudge={MODULE_NUDGES[module]}/>
            </div>
          )}
        </div>
      </div>

      {/* ── OVERLAYS ── */}
      {gameTheoryOpen && (
        <GameTheoryMode
          problem={problem} issues={issues} decisions={decisions}
          strategies={strategies}
          onClose={()=>setGameTheoryOpen(false)}
          aiCall={aiCall} aiBusy={aiBusy} onAIMsg={pushAIMsg}/>
      )}

      {/* ── Comments Panel ── */}
      {showComments && decisionId && (
        <div style={{ position:"fixed", right:0, top:0, bottom:0,
          zIndex:200, display:"flex", flexDirection:"column" }}>
          <CommentsPanel
            decisionId={decisionId}
            module={module}
            currentUser={currentUser}
            onClose={()=>setShowComments(false)}/>
        </div>
      )}

      {workshopOpen && (
        <WorkshopMode problem={problem} issues={issues} decisions={decisions} strategies={strategies} criteria={criteria} onIssues={setIssues} onStrategies={setStrategies} onExit={()=>setWorkshopOpen(false)} aiCall={aiCall} aiBusy={aiBusy} onAIMsg={pushAIMsg}/>
      )}
      {versionOpen && (
        <VersionPanel
          currentData={{ problem, issues, decisions, criteria, strategies, assessmentScores, dqScores }}
          onRestore={(data)=>{
            if(data.problem)    setProblem(data.problem);
            if(data.issues)     setIssues(data.issues);
            if(data.decisions)  setDecisions(data.decisions);
            if(data.criteria)   setCriteria(data.criteria);
            if(data.strategies) setStrategies(data.strategies);
            if(data.assessmentScores) setAssessmentScores(data.assessmentScores);
            if(data.dqScores)   setDqScores(data.dqScores);
          }}
          onClose={()=>setVersionOpen(false)}/>
      )}
      {/* ── Decision Picker ── */}
      {showDecisions && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,.5)",
          zIndex:600, display:"flex", alignItems:"center", justifyContent:"center" }}
          onClick={()=>setShowDecisions(false)}>
          <div style={{ background:DS.canvas, borderRadius:12, width:560,
            maxHeight:"70vh", overflow:"hidden", display:"flex", flexDirection:"column",
            boxShadow:"0 24px 60px rgba(0,0,0,.3)" }}
            onClick={e=>e.stopPropagation()}>
            <div style={{ padding:"16px 20px", borderBottom:`1px solid ${DS.canvasBdr}`,
              display:"flex", alignItems:"center", gap:12 }}>
              <div style={{ fontFamily:"'Libre Baskerville',serif", fontSize:16,
                fontWeight:700, color:DS.ink, flex:1 }}>Open Decision</div>
              <button onClick={()=>setShowDecisions(false)}
                style={{ background:"none",border:"none",cursor:"pointer",
                  color:DS.inkTer,fontSize:18 }}>×</button>
            </div>
            <div style={{ overflow:"auto", padding:"8px 0" }}>
              {decisionList.length===0?(
                <div style={{ padding:"32px", textAlign:"center", color:DS.inkTer, fontSize:13, lineHeight:1.7 }}>
                  {_SB_URL
                    ? "No saved decisions yet. Start working and your decision will auto-save."
                    : <><strong style={{color:DS.ink,display:"block",marginBottom:8}}>Cloud sync not configured</strong>Decisions save to this browser session only. To enable cross-device sharing, configure Supabase in your Vercel environment variables.</>
                  }
                </div>
              ):(
                decisionList.map(row=>(
                  <div key={row.id}
                    onClick={()=>{
                      window.location.href = window.location.pathname + "?d=" + row.id;
                    }}
                    style={{ padding:"12px 20px", cursor:"pointer", borderBottom:`1px solid ${DS.canvasBdr}`,
                      display:"flex", alignItems:"center", gap:12,
                      background:"transparent", transition:"background .1s" }}
                    onMouseEnter={e=>e.currentTarget.style.background=DS.canvasAlt}
                    onMouseLeave={e=>e.currentTarget.style.background="transparent"}>
                    <div style={{ flex:1 }}>
                      <div style={{ fontSize:13, fontWeight:700, color:DS.ink, marginBottom:2 }}>
                        {row.project_name || "Untitled Decision"}
                      </div>
                      <div style={{ fontSize:10, color:DS.inkTer }}>
                        Last updated: {new Date(row.updated_at).toLocaleDateString("en-GB",{day:"numeric",month:"short",year:"numeric",hour:"2-digit",minute:"2-digit"})}
                      </div>
                    </div>
                    <div style={{ fontSize:10, color:DS.inkTer, fontFamily:"monospace" }}>
                      {row.id.slice(0,8)}…
                    </div>
                  </div>
                ))
              )}
            </div>
            <div style={{ padding:"12px 20px", borderTop:`1px solid ${DS.canvasBdr}`,
              display:"flex", justifyContent:"space-between", alignItems:"center" }}>
              <button
                onClick={()=>{
                  window.location.href = window.location.pathname;
                }}
                style={{ fontSize:11, fontWeight:700, fontFamily:"inherit",
                  padding:"6px 14px", border:`1px solid ${DS.canvasBdr}`,
                  borderRadius:6, background:"transparent",
                  color:DS.inkSub, cursor:"pointer" }}>
                + New Decision
              </button>
              <div style={{ fontSize:10, color:DS.inkTer }}>
                {decisionList.length} saved decision{decisionList.length!==1?"s":""}
              </div>
            </div>
          </div>
        </div>
      )}

      {dqiOpen && (
        <DQiDashboard currentProject={problem} dqScores={dqScores}
          strategies={strategies} issues={issues}
          aiCall={aiCall} aiBusy={aiBusy} onClose={()=>setDqiOpen(false)}/>
      )}
      {projectSetupOpen && (
        <ProjectSetupModal data={problem} onChange={setProblem}
          onClose={()=>setProjectSetupOpen(false)}/>
      )}
    </div>
  );
}


export default function App() {
  if (typeof window !== "undefined" &&
      new URLSearchParams(window.location.search).get("ws_projector") === "1") {
    return <ProjectorView/>;
  }
  return <AppMain/>;
}
